#nullable enable
using Microsoft.Build.Construction;
using Microsoft.Build.Execution;
using System.Linq;
using System.Text;
using System.Text.Json;

namespace Bsharp.Codegen;

/// <summary>
/// Foundation-only Go host emitter. This is intentionally a thin shell:
/// it loads the project, walks the ProjectInstance, and emits a Go module
/// with stub target bodies plus a self-describing emit-report.json. It is
/// NOT a working build host yet; target bodies panic with
/// runtime.NotImplemented when invoked.
///
/// The point of this scaffold is to make every subsequent emission task
/// fail loudly at codegen time (or at runtime panic) so we can grow real
/// emission piece-by-piece without ever producing silently-wrong Go.
/// </summary>
internal static class GoEmitter {
    public static int Emit(
        ProjectInstance instance,
        string outDir,
        IReadOnlyList<string>? requestedTargets,
        Dictionary<string, string> globalProps,
        string runtimeReplacePath
    ) {
        Directory.CreateDirectory(outDir);
        var report = new EmitReport();

        var mainGo = BuildMainGo(instance, requestedTargets, report);
        var goMod = BuildGoMod(runtimeReplacePath);

        File.WriteAllText(Path.Combine(outDir, "main.go"), mainGo);
        File.WriteAllText(Path.Combine(outDir, "go.mod"), goMod);
        File.WriteAllText(Path.Combine(outDir, "emit-report.json"),
            JsonSerializer.Serialize(report, new JsonSerializerOptions { WriteIndented = true }));

        Console.Error.WriteLine($"codegen: --emit-go wrote main.go ({mainGo.Length} chars), go.mod, emit-report.json to {outDir}");
        Console.Error.WriteLine($"codegen: --emit-go status: {report.Targets.Total} targets ({report.Targets.RealBody} real-body, {report.Targets.StubBody} stub)");
        Console.Error.WriteLine($"codegen: --emit-go Phase A: complex targets still panic; see emit-report.json for per-reason counts.");
        return 0;
    }

    static string BuildMainGo(ProjectInstance instance, IReadOnlyList<string>? requestedTargets, EmitReport report) {
        var sb = new StringBuilder();
        sb.AppendLine("// Code generated by bsharp codegen --emit-go. DO NOT EDIT.");
        sb.AppendLine("//");
        sb.AppendLine("// Foundation scaffold only. Target bodies are NOT implemented; calling");
        sb.AppendLine("// any target will panic via runtime.NotImplemented. Use this file as a");
        sb.AppendLine("// shape reference for the real emitter that will land in follow-up work.");
        sb.AppendLine("package main");
        sb.AppendLine();
        sb.AppendLine("import (");
        sb.AppendLine("\t\"fmt\"");
        sb.AppendLine("\t\"os\"");
        sb.AppendLine("\t\"strings\"");
        sb.AppendLine();
        sb.AppendLine("\trt \"github.com/simonrozsival/bsharp-host-go/runtime\"");
        sb.AppendLine(")");
        sb.AppendLine();

        EmitProperties(sb, instance, report);
        EmitItems(sb, instance, report);
        EmitTargetStubs(sb, instance, report);
        EmitMain(sb, instance, requestedTargets);

        return sb.ToString();
    }

    static void EmitProperties(StringBuilder sb, ProjectInstance instance, EmitReport report) {
        var properties = instance.Properties
            .Where(p => !string.IsNullOrEmpty(p.Name))
            .OrderBy(p => p.Name, StringComparer.OrdinalIgnoreCase)
            .ToArray();
        report.Properties.Total = properties.Length;
        report.Properties.SupportedLiteral = 0;

        sb.AppendLine("// P captures the initial property snapshot. Real codegen will route");
        sb.AppendLine("// dynamic mutations through typed setters; for now it's a value-bag.");
        sb.AppendLine("type properties struct {");
        sb.AppendLine("\textras map[string]string");
        sb.AppendLine("}");
        sb.AppendLine();
        sb.AppendLine("func (p *properties) Get(name string) string {");
        sb.AppendLine("\tif p.extras == nil { return \"\" }");
        sb.AppendLine("\treturn p.extras[strings.ToLower(name)]");
        sb.AppendLine("}");
        sb.AppendLine("func (p *properties) Set(name, value string) {");
        sb.AppendLine("\tif p.extras == nil { p.extras = make(map[string]string) }");
        sb.AppendLine("\tp.extras[strings.ToLower(name)] = value");
        sb.AppendLine("}");
        sb.AppendLine();
        sb.AppendLine("var P = &properties{ extras: map[string]string{");
        foreach (var prop in properties) {
            sb.Append("\t\"").Append(prop.Name.ToLowerInvariant()).Append("\": ");
            sb.Append(GoStringLiteral(prop.EvaluatedValue));
            sb.AppendLine(",");
            report.Properties.SupportedLiteral++;
        }
        sb.AppendLine("}}");
        sb.AppendLine();
    }

    static void EmitItems(StringBuilder sb, ProjectInstance instance, EmitReport report) {
        var byType = instance.Items
            .GroupBy(i => i.ItemType, StringComparer.OrdinalIgnoreCase)
            .OrderBy(g => g.Key, StringComparer.OrdinalIgnoreCase)
            .ToArray();
        report.Items.TotalTypes = byType.Length;
        report.Items.TotalItems = instance.Items.Count;
        report.Items.SupportedLiteral = 0;

        sb.AppendLine("// I holds typed item lists, keyed by lowercased item type. Generated.");
        sb.AppendLine("type items struct {");
        sb.AppendLine("\tlists map[string][]*rt.Item");
        sb.AppendLine("}");
        sb.AppendLine();
        sb.AppendLine("func (it *items) Get(name string) []*rt.Item {");
        sb.AppendLine("\treturn it.lists[strings.ToLower(name)]");
        sb.AppendLine("}");
        sb.AppendLine("func (it *items) AppendTo(name string, more []*rt.Item) {");
        sb.AppendLine("\tk := strings.ToLower(name)");
        sb.AppendLine("\tit.lists[k] = append(it.lists[k], more...)");
        sb.AppendLine("}");
        sb.AppendLine("// RemoveByIdentity removes every item from list `name` whose Identity");
        sb.AppendLine("// matches identity. Used by emitted <ItemGroup><X Remove=\"...\"/></ItemGroup>.");
        sb.AppendLine("func (it *items) RemoveByIdentity(name, identity string) {");
        sb.AppendLine("\tk := strings.ToLower(name)");
        sb.AppendLine("\tlist := it.lists[k]");
        sb.AppendLine("\tif len(list) == 0 { return }");
        sb.AppendLine("\tkeep := list[:0]");
        sb.AppendLine("\tfor _, item := range list {");
        sb.AppendLine("\t\tif item.Identity != identity { keep = append(keep, item) }");
        sb.AppendLine("\t}");
        sb.AppendLine("\tit.lists[k] = keep");
        sb.AppendLine("}");
        sb.AppendLine();
        sb.AppendLine("var I = newItems()");
        sb.AppendLine();
        sb.AppendLine("func newItems() *items {");
        sb.AppendLine("\tit := &items{ lists: map[string][]*rt.Item{} }");
        foreach (var group in byType) {
            sb.Append("\tit.lists[\"").Append(group.Key.ToLowerInvariant()).Append("\"] = []*rt.Item{");
            var any = false;
            foreach (var item in group) {
                if (any) sb.Append(", ");
                sb.Append("rt.NewItem(").Append(GoStringLiteral(item.EvaluatedInclude)).Append(")");
                any = true;
                report.Items.SupportedLiteral++;
