    static void EmitTargetStubs(StringBuilder sb, ProjectInstance instance, EmitReport report) {
        // Preserve declaration order BEFORE we sort for file layout — extender
        // ordering depends on this (MSBuild docs: extenders run in the order
        // their target was declared).
        var targetsInDeclarationOrder = instance.Targets.Values.ToArray();
        var targets = targetsInDeclarationOrder
            .OrderBy(t => t.Name, StringComparer.OrdinalIgnoreCase)
            .ToArray();
        var (beforeExtenders, afterExtenders) = BuildExtenderMaps(targetsInDeclarationOrder);
        report.Targets.Total = targets.Length;
        report.Targets.RealBody = 0;
        report.Targets.StubBody = 0;
        report.Targets.UnsupportedReasons = new SortedDictionary<string, int>(StringComparer.Ordinal);
        var captureRejections = !string.IsNullOrEmpty(
            Environment.GetEnvironmentVariable("BSHARP_DEBUG_REJECTIONS"));

        var targetIndex = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        var nameSet = new HashSet<string>(StringComparer.Ordinal);
        foreach (var target in targets) {
            targetIndex[target.Name] = SanitizeTargetName(target.Name, nameSet);
        }

        sb.AppendLine("// Generated target functions. Each target is classified as one of:");
        sb.AppendLine("//   - real-body: emitted from MSBuild XML using runtime.Expand / runtime.EvalCondition");
        sb.AppendLine("//   - stub:      panics via runtime.NotImplemented (Phase A doesn't yet handle the construct)");
        sb.AppendLine("// See emit-report.json for the classification per target.");
        sb.AppendLine();

        foreach (var target in targets) {
            var ident = targetIndex[target.Name];
            var reason = ClassifyTarget(target);
            if (reason == null) {
                EmitRealTargetBody(sb, target, ident, targetIndex, beforeExtenders, afterExtenders);
                report.Targets.RealBody++;
            } else {
                EmitStubTargetBody(sb, target, ident, reason);
                report.Targets.StubBody++;
                report.Targets.UnsupportedReasons.TryGetValue(reason, out var c);
                report.Targets.UnsupportedReasons[reason] = c + 1;
                if (captureRejections) {
                    report.Targets.Rejected ??= new List<RejectedTarget>();
                    report.Targets.Rejected.Add(new RejectedTarget {
                        Name = target.Name,
                        Reason = reason,
                        Detail = DescribeRejection(target, reason),
                    });
                }
            }
        }

        sb.AppendLine("// dispatchTarget maps target names to functions. Generated.");
        sb.AppendLine("func dispatchTarget(name string) bool {");
        sb.AppendLine("\tswitch strings.ToLower(name) {");
        foreach (var target in targets) {
            sb.Append("\tcase ").Append(GoStringLiteral(target.Name.ToLowerInvariant())).Append(":");
            sb.AppendLine();
            sb.Append("\t\t").Append(targetIndex[target.Name]).AppendLine("()");
            sb.AppendLine("\t\treturn true");
        }
        sb.AppendLine("\t}");
        sb.AppendLine("\treturn false");
        sb.AppendLine("}");
        sb.AppendLine();
    }

    static void EmitStubTargetBody(StringBuilder sb, ProjectTargetInstance target, string ident, string reason) {
        sb.Append("// ").Append(target.Name).Append(": stub — ").AppendLine(reason);
        sb.Append("func ").Append(ident).AppendLine("() {");
        sb.Append("\trt.NotImplemented(").Append(GoStringLiteral(target.Name)).AppendLine(")");
        sb.AppendLine("\tpanic(\"target body not yet emitted: " + EscapeForGo(target.Name) + " — " + EscapeForGo(reason) + "\")");
        sb.AppendLine("}");
        sb.AppendLine();
    }

    static void EmitRealTargetBody(StringBuilder sb, ProjectTargetInstance target, string ident,
        Dictionary<string, string> targetIndex,
        Dictionary<string, List<string>> beforeExtenders,
        Dictionary<string, List<string>> afterExtenders)
    {
        beforeExtenders.TryGetValue(target.Name, out var befores);
        afterExtenders.TryGetValue(target.Name, out var afters);
        var hasBefores = befores is { Count: > 0 };
        var hasAfters = afters is { Count: > 0 };
        var hasCond = !string.IsNullOrWhiteSpace(target.Condition);
        var hasIO = !string.IsNullOrWhiteSpace(target.Inputs) || !string.IsNullOrWhiteSpace(target.Outputs);

        sb.Append("// ").Append(target.Name).AppendLine(": real body");
        sb.Append("func ").Append(ident).AppendLine("() {");
        sb.Append("\tts := rt.GetTargetState(").Append(GoStringLiteral(target.Name)).AppendLine(")");
        sb.AppendLine("\tif !ts.TryEnter() { return }");

        if (!string.IsNullOrWhiteSpace(target.DependsOnTargets)) {
            var dot = target.DependsOnTargets;
            if (dot.Contains('$')) {
                // Dynamic depends-on: expand the template at runtime and
                // dispatch by name. Order is preserved; duplicates are kept
                // (MSBuild may legitimately re-attempt a target after an
                // intervening mutation — TargetState's TryEnter handles the
                // "already done" short-circuit). Unknown names panic loudly.
                sb.Append("\tfor _, dep := range rt.SplitSemicolon(rt.MustExpand(")
                  .Append(GoStringLiteral(dot))
                  .AppendLine(", P, I, nil)) {");
                sb.AppendLine("\t\tif dep == \"\" { continue }");
                sb.Append("\t\tif !dispatchTarget(dep) { panic(fmt.Sprintf(")
                  .Append(GoStringLiteral("DependsOnTargets: unknown target %q referenced by " + target.Name))
                  .AppendLine(", dep)) }");
                sb.AppendLine("\t}");
            } else {
                foreach (var dep in dot.Split(';', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)) {
                    if (targetIndex.TryGetValue(dep, out var depIdent)) {
                        sb.Append("\t").Append(depIdent).AppendLine("()")
                          .Append("");
                    }
                }
            }
        }

        // Phase E: before-extenders (literal only — dynamic extender attrs are
        // rejected by ClassifyTarget). They run unconditionally after the
        // depends-on chain, regardless of this target's condition.
        if (hasBefores) {
            foreach (var be in befores!) {
                if (targetIndex.TryGetValue(be, out var beIdent)) {
                    sb.Append("\t").Append(beIdent).AppendLine("()");
                }
            }
        }

        if (!hasBefores && !hasAfters) {
            // Fast path: no extenders, keep the existing early-return shape.
            if (hasCond) {
                sb.Append("\tif !rt.MustEvalCondition(").Append(GoStringLiteral(target.Condition)).AppendLine(", P, I) { ts.MarkSkipped(); return }");
            }
            EmitTargetBodyOrIncremental(sb, target, hasIO);
            sb.AppendLine("\tts.MarkDone()");
        } else {
            // Extender path: keep TargetState in `running` until after-extenders
            // finish. Calling MarkSkipped before after-extenders would reset
            // state to pending and allow an after-extender's DependsOnTargets to
            // immediately re-enter the same target, producing recursion that
            // MSBuild avoids.
            if (hasCond) {
                sb.Append("\tcondOk := rt.MustEvalCondition(").Append(GoStringLiteral(target.Condition)).AppendLine(", P, I)");
                sb.AppendLine("\tif condOk {");
            }
            // Body emitted at \t (child emitters hardcode \t indent). When the
            // condition wraps the body, the resulting code is visually
            // mis-indented but valid Go.
            EmitTargetBodyOrIncremental(sb, target, hasIO);
            sb.AppendLine("\tts.MarkDone()");
            if (hasCond) {
                sb.AppendLine("\t}");
            }
            if (hasAfters) {
                foreach (var ae in afters!) {
                    if (targetIndex.TryGetValue(ae, out var aeIdent)) {
                        sb.Append("\t").Append(aeIdent).AppendLine("()");
                    }
                }
            }
            if (hasCond) {
                sb.AppendLine("\tif !condOk { ts.MarkSkipped() }");
            }
        }

        sb.AppendLine("}");
        sb.AppendLine();
    }

    // EmitTargetBodyOrIncremental emits either the unconditional body (started
    // → children → finished) or the Phase D incremental shape:
    //
    //     if !rt.IsUpToDate(name, inputs, outputs) {
    //         started := ...; <children>; finished := ...
    //     } else {
    //         rt.Log.TargetUpToDate(name)
    //         <output inference: PG/IG only — task <Output/> is rejected at classifier>
    //     }
    //
    // MarkDone() is emitted by the caller, AFTER this block, regardless of
    // branch. Up-to-date is a successful terminal completion; downstream
    // targets must not re-run the target.
    static void EmitTargetBodyOrIncremental(StringBuilder sb, ProjectTargetInstance target, bool hasIO) {
        if (hasIO) {
            sb.Append("\tif !rt.IsUpToDate(").Append(GoStringLiteral(target.Name))
              .Append(", rt.MustExpand(").Append(GoStringLiteral(target.Inputs ?? "")).Append(", P, I, nil)")
              .Append(", rt.MustExpand(").Append(GoStringLiteral(target.Outputs ?? "")).AppendLine(", P, I, nil)) {");
            sb.Append("\tstarted := rt.Log.TargetStarted(").Append(GoStringLiteral(target.Name)).AppendLine(")");
            EmitTargetChildren(sb, target);
            sb.Append("\trt.Log.TargetFinished(").Append(GoStringLiteral(target.Name)).AppendLine(", started)");
            sb.AppendLine("\t} else {");
            sb.Append("\trt.Log.TargetUpToDate(").Append(GoStringLiteral(target.Name)).AppendLine(")");
            EmitTargetChildrenForUpToDateSkip(sb, target);
            sb.AppendLine("\t}");
        } else {
            sb.Append("\tstarted := rt.Log.TargetStarted(").Append(GoStringLiteral(target.Name)).AppendLine(")");
            EmitTargetChildren(sb, target);
            sb.Append("\trt.Log.TargetFinished(").Append(GoStringLiteral(target.Name)).AppendLine(", started)");
        }
    }

    static void EmitTargetChildren(StringBuilder sb, ProjectTargetInstance target) {
        foreach (var child in target.Children) {
            switch (child) {
                case ProjectTaskInstance task:
                    EmitLocalTaskCall(sb, target, task);
                    break;
                case ProjectPropertyGroupTaskInstance pg:
                    EmitPropertyGroup(sb, pg);
                    break;
                case ProjectItemGroupTaskInstance ig:
                    EmitItemGroup(sb, ig);
                    break;
            }
        }
    }

    // EmitTargetChildrenForUpToDateSkip emits the "output inference" pass
    // MSBuild applies when a target is skipped as up-to-date: PropertyGroup
    // and ItemGroup mutations are re-applied so downstream targets see the
    // same state they would see if the target had executed. Tasks are
    // intentionally NOT emitted: targets containing a task with <Output/> are
    // rejected at classifier level (task-has-outputs:X), and tasks without
    // outputs have no state to infer.
    static void EmitTargetChildrenForUpToDateSkip(StringBuilder sb, ProjectTargetInstance target) {
        foreach (var child in target.Children) {
            switch (child) {
                case ProjectPropertyGroupTaskInstance pg:
                    EmitPropertyGroup(sb, pg);
                    break;
                case ProjectItemGroupTaskInstance ig:
                    EmitItemGroup(sb, ig);
                    break;
            }
        }
    }



    static void EmitPropertyGroup(StringBuilder sb, ProjectPropertyGroupTaskInstance pg) {
        var hasOuterCond = !string.IsNullOrWhiteSpace(pg.Condition);
        var indent = "\t";
        if (hasOuterCond) {
            sb.Append(indent).Append("if rt.MustEvalCondition(").Append(GoStringLiteral(pg.Condition)).AppendLine(", P, I) {");
            indent = "\t\t";
        }
        foreach (var prop in pg.Properties) {
            var hasCond = !string.IsNullOrWhiteSpace(prop.Condition);
            if (hasCond) {
                sb.Append(indent).Append("if rt.MustEvalCondition(").Append(GoStringLiteral(prop.Condition)).AppendLine(", P, I) {");
                sb.Append(indent).Append("\tP.Set(").Append(GoStringLiteral(prop.Name)).Append(", rt.MustExpand(")
                  .Append(GoStringLiteral(prop.Value)).AppendLine(", P, I, nil))");
                sb.Append(indent).AppendLine("}");
            } else {
                sb.Append(indent).Append("P.Set(").Append(GoStringLiteral(prop.Name)).Append(", rt.MustExpand(")
                  .Append(GoStringLiteral(prop.Value)).AppendLine(", P, I, nil))");
            }
        }
        if (hasOuterCond) sb.AppendLine("\t}");
    }

    static void EmitItemGroup(StringBuilder sb, ProjectItemGroupTaskInstance ig) {
        var hasOuterCond = !string.IsNullOrWhiteSpace(ig.Condition);
        var indent = "\t";
        if (hasOuterCond) {
            sb.Append(indent).Append("if rt.MustEvalCondition(").Append(GoStringLiteral(ig.Condition)).AppendLine(", P, I) {");
            indent = "\t\t";
        }
        foreach (var item in ig.Items) {
            EmitItemGroupChild(sb, item, indent);
        }
        if (hasOuterCond) sb.AppendLine("\t}");
    }

    static void EmitItemGroupChild(StringBuilder sb, ProjectItemGroupTaskItemInstance item, string indent) {
        var hasCond = !string.IsNullOrWhiteSpace(item.Condition);
        // Batched per-item path: when the condition, include/remove spec,
        // or any metadata references `%()` outside an `@()` transform, the
        // ItemGroup is per-item-batched. The classifier guarantees we can
        // determine a single source list (Include/Remove `@(SrcList)`, or
        // ItemType when both are empty, or a single qualifier extracted
        // from the cond/metadata refs).
        if (ItemNeedsBatchedEmission(item)) {
            EmitBatchedItemGroupChild(sb, item, indent);
            return;
        }
        var bodyIndent = indent;
        if (hasCond) {
            sb.Append(indent).Append("if rt.MustEvalCondition(").Append(GoStringLiteral(item.Condition)).AppendLine(", P, I) {");
            bodyIndent = indent + "\t";
        }

        var include = item.Include ?? "";
        var remove = item.Remove ?? "";
        var exclude = item.Exclude ?? "";
        var itemType = item.ItemType;

        if (include.Length > 0) {
            // If Exclude is present, build a string-set of excluded identities
            // up-front so the include loop can filter in O(1) per candidate.
            // Identities are compared case-sensitively (MSBuild's actual
            // semantics are case-insensitive on Windows / case-sensitive on
            // Unix, but our closed-world targets exclude via either literal
            // paths or @() lists where the source identities are already
            // canonical, so case-sensitive is safe for the current fixtures).
            //
            // The whole Exclude+Include emission is wrapped in its own Go
            // block so the `excluded` local doesn't collide when the same
            // target body contains multiple <ItemGroup>s that each use
            // Exclude (e.g. IncrementalClean).
            var hasExclude = exclude.Length > 0;
            if (hasExclude) {
                sb.Append(bodyIndent).AppendLine("{");
                bodyIndent = bodyIndent + "\t";
                sb.Append(bodyIndent).Append("excluded := make(map[string]struct{})").AppendLine();
                sb.Append(bodyIndent).Append("for _, ex := range rt.SplitSemicolon(rt.MustExpand(")
                  .Append(GoStringLiteral(exclude)).AppendLine(", P, I, nil)) {");
                sb.Append(bodyIndent).AppendLine("\tif ex != \"\" { excluded[ex] = struct{}{} }");
                sb.Append(bodyIndent).AppendLine("}");
            }
            var kind = ClassifyItemIncludeSpec(include);
            if (kind == ItemIncludeKind.ItemListCopy) {
                var sourceType = include.Trim().Substring(2, include.Trim().Length - 3).Trim();
                sb.Append(bodyIndent).Append("for _, src := range I.Get(").Append(GoStringLiteral(sourceType)).AppendLine(") {");
                if (hasExclude) {
                    sb.Append(bodyIndent).AppendLine("\tif _, skip := excluded[src.Identity]; skip { continue }");
                }
                sb.Append(bodyIndent).AppendLine("\titem := src.Clone()");
                EmitItemMetadata(sb, item, bodyIndent + "\t", "item");
                sb.Append(bodyIndent).Append("\tI.AppendTo(").Append(GoStringLiteral(itemType)).AppendLine(", []*rt.Item{item})");
                sb.Append(bodyIndent).AppendLine("}");
            } else if (kind == ItemIncludeKind.ItemListFilter) {
                var trimmed = include.Trim();
                var inner = trimmed.Substring(2, trimmed.Length - 3);
                if (!TryParseWithMetadataValueInclude(inner, out var spec) || spec == null) {
                    // Should never happen — the classifier already accepted
                    // this shape. Defensive panic so a future regression is
                    // loud rather than silently wrong.
                    throw new InvalidOperationException("ItemListFilter classified but re-parse failed: " + include);
                }
                sb.Append(bodyIndent).Append("for _, src := range I.Get(").Append(GoStringLiteral(spec.SourceItemType)).AppendLine(") {");
                if (hasExclude) {
                    sb.Append(bodyIndent).AppendLine("\tif _, skip := excluded[src.Identity]; skip { continue }");
                }
                // MSBuild's WithMetadataValue is case-insensitive on the
                // metadata value. The metadata KEY is also case-insensitive
                // (Item.GetMetadata already handles that).
                sb.Append(bodyIndent).Append("\tif !strings.EqualFold(src.GetMetadata(")
                  .Append(GoStringLiteral(spec.MetaName)).Append("), rt.MustExpand(")
                  .Append(GoStringLiteral(spec.ValueTemplate)).AppendLine(", P, I, nil)) { continue }");
                sb.Append(bodyIndent).AppendLine("\titem := src.Clone()");
                EmitItemMetadata(sb, item, bodyIndent + "\t", "item");
                sb.Append(bodyIndent).Append("\tI.AppendTo(").Append(GoStringLiteral(itemType)).AppendLine(", []*rt.Item{item})");
                sb.Append(bodyIndent).AppendLine("}");
            } else {
                // Literal/expansion path: expand, split, create items with metadata.
                sb.Append(bodyIndent).Append("for _, id := range rt.SplitSemicolon(rt.MustExpand(")
                  .Append(GoStringLiteral(include)).AppendLine(", P, I, nil)) {");
                if (hasExclude) {
                    sb.Append(bodyIndent).AppendLine("\tif _, skip := excluded[id]; skip { continue }");
                }
                sb.Append(bodyIndent).AppendLine("\titem := rt.NewItem(id)");
                EmitItemMetadata(sb, item, bodyIndent + "\t", "item");
                sb.Append(bodyIndent).Append("\tI.AppendTo(").Append(GoStringLiteral(itemType)).AppendLine(", []*rt.Item{item})");
                sb.Append(bodyIndent).AppendLine("}");
            }
            if (hasExclude) {
                bodyIndent = bodyIndent.Substring(0, bodyIndent.Length - 1);
                sb.Append(bodyIndent).AppendLine("}");
            }
        } else if (remove.Length > 0) {
            sb.Append(bodyIndent).Append("for _, id := range rt.SplitSemicolon(rt.MustExpand(")
              .Append(GoStringLiteral(remove)).AppendLine(", P, I, nil)) {");
            sb.Append(bodyIndent).Append("\tI.RemoveByIdentity(").Append(GoStringLiteral(itemType)).AppendLine(", id)");
            sb.Append(bodyIndent).AppendLine("}");
        } else if (item.Metadata.Count > 0) {
            // Modify-metadata path: <ItemGroup><X><Meta>v</Meta></X></ItemGroup>
            // with no Include/Remove updates metadata on EVERY existing item
            // of type X (MSBuild ItemGroupIntrinsicTask.ExecuteModify).
            sb.Append(bodyIndent).Append("for _, item := range I.Get(").Append(GoStringLiteral(itemType)).AppendLine(") {");
            EmitItemMetadata(sb, item, bodyIndent + "\t", "item");
            sb.Append(bodyIndent).AppendLine("}");
        }

        if (hasCond) sb.Append(indent).AppendLine("}");
    }

    // ItemNeedsBatchedEmission returns true when the item references `%()`
    // anywhere that requires per-item iteration to evaluate: condition,
    // Include/Remove spec, or any metadata Value/Condition. `ContainsBatching`
    // correctly skips inside `@(X->'...')` transforms so this only triggers
    // on genuine batching refs.
    static bool ItemNeedsBatchedEmission(ProjectItemGroupTaskItemInstance item) {
        if (ContainsBatching(item.Condition)) return true;
        if (ContainsBatching(item.Include)) return true;
        if (ContainsBatching(item.Remove)) return true;
        foreach (var m in item.Metadata) {
            if (ContainsBatching(m.Value)) return true;
            if (ContainsBatching(m.Condition)) return true;
        }
        return false;
    }

    // ComputeBatchSrcList mirrors the classifier's source-list resolution
    // for an item that the dispatcher has decided needs batched emission.
    // Returns null only if the classifier missed something (defensive —
    // callers should treat null as a bug since the dispatcher already
    // gated on the classifier's acceptance).
    static string? ComputeBatchSrcList(ProjectItemGroupTaskItemInstance item) {
        var rawInc = item.Include ?? "";
        var rawRem = item.Remove ?? "";
        if (rawInc.Length > 0 && ClassifyItemIncludeSpec(rawInc) == ItemIncludeKind.ItemListCopy) {
            var trimmed = rawInc.Trim();
            var ident = trimmed.Substring(2, trimmed.Length - 3).Trim();
            if (IsSimpleIdentifierName(ident)) return ident;
        } else if (rawInc.Length == 0 && rawRem.Length > 0
                   && ClassifyItemIncludeSpec(rawRem) == ItemIncludeKind.ItemListCopy) {
            var trimmed = rawRem.Trim();
            var ident = trimmed.Substring(2, trimmed.Length - 3).Trim();
            if (IsSimpleIdentifierName(ident)) return ident;
        } else if (rawInc.Length == 0 && rawRem.Length == 0) {
            return item.ItemType;
        } else if (rawInc.Length > 0) {
            var fromTransform = TryGetTransformIncludeSrcList(rawInc);
            if (fromTransform != null) return fromTransform;
        }
        var fromCond = ExtractSingleBatchQualifier(item.Condition ?? "");
        if (fromCond != null) return fromCond;
        foreach (var meta in item.Metadata) {
            var q = ExtractSingleBatchQualifier(meta.Value ?? "")
                 ?? ExtractSingleBatchQualifier(meta.Condition ?? "");
            if (q != null) return q;
        }
        return null;
    }

    // ComputeTaskBatchSrcList resolves the single source-list qualifier for
    // a task whose condition or any parameter value contains `%(...)`. The
    // result is the item-type name to iterate over at runtime; condition
    // and parameter values then expand against each source item's metadata.
    // Returns null when no batching refs are found OR when refs use more
    // than one distinct qualifier (cross-list batching is unsupported).
    //
    // All qualified refs must agree on the qualifier; unqualified refs
    // (`%(Identity)` etc.) are tolerated and resolve against the chosen
    // source list at runtime. Returns null when only unqualified refs
    // exist, because we cannot guess the source list — those cases need
    // implicit-source resolution from the surrounding target context, which
    // we don't model.
    static string? ComputeTaskBatchSrcList(ProjectTaskInstance task) {
        var fromCond = ExtractSingleBatchQualifier(task.Condition ?? "");
        string? found = fromCond;
        foreach (var p in task.Parameters) {
            var q = ExtractSingleBatchQualifier(p.Value ?? "");
            if (q == null) continue;
            if (found == null) {
                found = q;
            } else if (!string.Equals(found, q, StringComparison.OrdinalIgnoreCase)) {
                return null;
            }
        }
        return found;
    }


    // EmitBatchedItemGroupChild emits a per-item iteration when an item
    // requires batched evaluation. The classifier guarantees a single
    // source list can be resolved; the loop iterates over `I.Get(SrcList)`
    // and threads each source item's metadata bag (`meta`) into condition
    // evaluation and metadata expansion.
    //
    // Includes/Removes/modify-meta are routed:
    //   - Include="@(SrcList)" → append a clone of each matching source item.
    //   - Include=literal/expr  → expand Include per iteration (may reference
    //                              `%(SrcList.M)`) and append a fresh item.
    //   - Remove="@(SrcList)"   → collect identities first, then bulk-remove.
    //   - No Include/Remove     → modify metadata on existing items in place.
    //
    // The whole emission lives in a Go block so the `excluded` / `meta` /
    // `item` locals don't collide with sibling ItemGroup children.
    static void EmitBatchedItemGroupChild(StringBuilder sb, ProjectItemGroupTaskItemInstance item, string indent) {
        var include = item.Include ?? "";
        var remove = item.Remove ?? "";
        var exclude = item.Exclude ?? "";
        var hasExclude = exclude.Length > 0;
        var itemType = item.ItemType;
        var isInclude = include.Length > 0;
        var isRemove = !isInclude && remove.Length > 0;
        var isModifyMeta = !isInclude && !isRemove;
        var hasCond = !string.IsNullOrWhiteSpace(item.Condition);

        var srcList = ComputeBatchSrcList(item)
            ?? throw new InvalidOperationException(
                $"batched emission requested but no source list resolved for item type {itemType}");

        // Is the Include literal-shaped (not @(SrcList))? Only meaningful when
        // isInclude. Detected by checking the classified include kind.
        var includeKind = isInclude ? ClassifyItemIncludeSpec(include) : ItemIncludeKind.Unsupported;
        var includeIsTransform = isInclude && includeKind != ItemIncludeKind.ItemListCopy
            && TryGetTransformIncludeSrcList(include) != null;
        var includeIsLiteral = isInclude && includeKind != ItemIncludeKind.ItemListCopy && !includeIsTransform;

        sb.Append(indent).AppendLine("{");
        var bi = indent + "\t";
        if (hasExclude) {
            sb.Append(bi).AppendLine("excluded := make(map[string]struct{})");
            sb.Append(bi).Append("for _, ex := range rt.SplitSemicolon(rt.MustExpand(")
              .Append(GoStringLiteral(exclude)).AppendLine(", P, I, nil)) {");
            sb.Append(bi).AppendLine("\tif ex != \"\" { excluded[ex] = struct{}{} }");
            sb.Append(bi).AppendLine("}");
        }
        if (isRemove) {
            sb.Append(bi).AppendLine("var toRemove []string");
            sb.Append(bi).Append("for _, src := range I.Get(").Append(GoStringLiteral(srcList)).AppendLine(") {");
            sb.Append(bi).AppendLine("\tmeta := rt.ItemBatchMeta(src)");
            if (hasCond) {
                sb.Append(bi).Append("\tif !rt.MustEvalConditionWithMeta(")
                  .Append(GoStringLiteral(item.Condition!)).AppendLine(", P, I, meta) { continue }");
            } else {
                sb.Append(bi).AppendLine("\t_ = meta");
            }
            if (hasExclude) {
                sb.Append(bi).AppendLine("\tif _, skip := excluded[src.Identity]; skip { continue }");
            }
            sb.Append(bi).AppendLine("\ttoRemove = append(toRemove, src.Identity)");
            sb.Append(bi).AppendLine("}");
            sb.Append(bi).AppendLine("for _, id := range toRemove {");
            sb.Append(bi).Append("\tI.RemoveByIdentity(").Append(GoStringLiteral(itemType)).AppendLine(", id)");
            sb.Append(bi).AppendLine("}");
            sb.Append(indent).AppendLine("}");
            return;
        }
        sb.Append(bi).Append("for _, src := range I.Get(").Append(GoStringLiteral(srcList)).AppendLine(") {");
        sb.Append(bi).AppendLine("\tmeta := rt.ItemBatchMeta(src)");
        if (hasCond) {
            sb.Append(bi).Append("\tif !rt.MustEvalConditionWithMeta(")
              .Append(GoStringLiteral(item.Condition!)).AppendLine(", P, I, meta) { continue }");
        }
        if (hasExclude) {
            sb.Append(bi).AppendLine("\tif _, skip := excluded[src.Identity]; skip { continue }");
        }
        if (isModifyMeta) {
            sb.Append(bi).AppendLine("\titem := src");
            EmitItemMetadata(sb, item, bi + "\t", "item", "meta");
        } else if (includeIsTransform) {
            // Include="@(SrcList->'tpl')" — evaluate the template alone
            // against src's meta to produce the identity string (matches
            // MSBuild's per-item transform). Split on ';' to support
            // templates that may produce multiple identities (rare but
            // legal). New items don't inherit src's metadata (the
            // transform produces only Identity); explicit <Meta> children
            // are applied below via EmitItemMetadata.
            var tpl = TryGetTransformIncludeTemplate(include)
                ?? throw new InvalidOperationException("transform-include re-parse failed: " + include);
            sb.Append(bi).Append("\tfor _, id := range rt.SplitSemicolon(rt.MustExpand(")
              .Append(GoStringLiteral(tpl)).AppendLine(", P, I, meta)) {");
            sb.Append(bi).AppendLine("\t\tif id == \"\" { continue }");
            sb.Append(bi).AppendLine("\t\titem := rt.NewItem(id)");
            EmitItemMetadata(sb, item, bi + "\t\t", "item", "meta");
            sb.Append(bi).Append("\t\tI.AppendTo(").Append(GoStringLiteral(itemType)).AppendLine(", []*rt.Item{item})");
            sb.Append(bi).AppendLine("\t}");
        } else if (includeIsLiteral) {
            // Expand the Include per source item, splitting on ';' to support
            // expressions like `"a;b"` that should produce multiple items.
            sb.Append(bi).Append("\tfor _, id := range rt.SplitSemicolon(rt.MustExpand(")
              .Append(GoStringLiteral(include)).AppendLine(", P, I, meta)) {");
            sb.Append(bi).AppendLine("\t\tif id == \"\" { continue }");
            sb.Append(bi).AppendLine("\t\titem := rt.NewItem(id)");
            EmitItemMetadata(sb, item, bi + "\t\t", "item", "meta");
            sb.Append(bi).Append("\t\tI.AppendTo(").Append(GoStringLiteral(itemType)).AppendLine(", []*rt.Item{item})");
            sb.Append(bi).AppendLine("\t}");
        } else {
            // Include="@(SrcList)" — clone the source item per iteration.
            sb.Append(bi).AppendLine("\titem := src.Clone()");
            EmitItemMetadata(sb, item, bi + "\t", "item", "meta");
            sb.Append(bi).Append("\tI.AppendTo(").Append(GoStringLiteral(itemType)).AppendLine(", []*rt.Item{item})");
        }
        if (!hasCond && !hasExclude && isModifyMeta && item.Metadata.Count == 0) {
            // Pathological — shouldn't reach here, but suppress unused.
            sb.Append(bi).AppendLine("\t_ = meta");
        }
        sb.Append(bi).AppendLine("}");
        sb.Append(indent).AppendLine("}");
    }

    static void EmitItemMetadata(StringBuilder sb, ProjectItemGroupTaskItemInstance item, string indent, string itemVar)
        => EmitItemMetadata(sb, item, indent, itemVar, batchMetaVar: null);

    // EmitItemMetadata emits the per-metadata SetMetadata calls. When
    // `batchMetaVar` is non-null, metadata Conditions and Values are
    // evaluated/expanded with that variable as the per-item batch bag
    // — required for `%(SrcList.M)` references inside batched ItemGroups.
    static void EmitItemMetadata(StringBuilder sb, ProjectItemGroupTaskItemInstance item, string indent, string itemVar, string? batchMetaVar) {
        var metaArg = batchMetaVar ?? "nil";
        foreach (var meta in item.Metadata) {
            var hasMetaCond = !string.IsNullOrWhiteSpace(meta.Condition);
            if (hasMetaCond) {
                if (batchMetaVar != null) {
                    sb.Append(indent).Append("if rt.MustEvalConditionWithMeta(")
                      .Append(GoStringLiteral(meta.Condition)).Append(", P, I, ")
                      .Append(batchMetaVar).AppendLine(") {");
                } else {
                    sb.Append(indent).Append("if rt.MustEvalCondition(")
                      .Append(GoStringLiteral(meta.Condition)).AppendLine(", P, I) {");
                }
                sb.Append(indent).Append("\t").Append(itemVar).Append(".SetMetadata(").Append(GoStringLiteral(meta.Name))
                  .Append(", rt.MustExpand(").Append(GoStringLiteral(meta.Value)).Append(", P, I, ")
                  .Append(metaArg).AppendLine("))");
                sb.Append(indent).AppendLine("}");
            } else {
                sb.Append(indent).Append(itemVar).Append(".SetMetadata(").Append(GoStringLiteral(meta.Name))
                  .Append(", rt.MustExpand(").Append(GoStringLiteral(meta.Value)).Append(", P, I, ")
                  .Append(metaArg).AppendLine("))");
            }
        }
    }

    static void EmitLocalTaskCall(StringBuilder sb, ProjectTargetInstance target, ProjectTaskInstance task) {
        // CallTarget is special — it doesn't have a runtime helper; it
        // dispatches to other targets emitted in this same file.
        if (string.Equals(task.Name, "CallTarget", StringComparison.OrdinalIgnoreCase)) {
            EmitCallTargetTask(sb, target, task);
            return;
        }

        // JoinItems uses a typed Left/Right []*Item signature (the standard
        // ParamList path can't preserve item metadata). The classifier has
        // already validated the supported shape.
        if (string.Equals(task.Name, "JoinItems", StringComparison.OrdinalIgnoreCase)) {
            EmitJoinItemsTask(sb, target, task);
            return;
        }

        var fn = LocalTaskGoFunc(task.Name);
        if (fn == null) {
            sb.Append("\trt.NotImplemented(").Append(GoStringLiteral(target.Name + ":" + task.Name)).AppendLine(")");
            return;
        }

        // Task-level batching: the classifier accepted this task with a
        // resolvable single source-list qualifier. Emit a per-source loop
        // that threads `meta` into both the condition and each parameter
        // value expansion. The whole emission lives in its own Go block
        // so the loop locals don't collide with sibling tasks/IGs.
        var taskSrcList = ComputeTaskBatchSrcList(task);
        if (taskSrcList != null) {
            EmitBatchedLocalTaskCall(sb, target, task, fn, taskSrcList);
            return;
        }

        if (!string.IsNullOrWhiteSpace(task.Condition)) {
            sb.Append("\tif rt.MustEvalCondition(").Append(GoStringLiteral(task.Condition)).AppendLine(", P, I) {");
        }

        sb.Append("\tif err := rt.").Append(fn).Append("(rt.NewParamList(");
        var first = true;
        foreach (var param in task.Parameters) {
            if (!first) sb.Append(", ");
            first = false;
            sb.Append("rt.Param{Key: ").Append(GoStringLiteral(param.Key))
              .Append(", Value: rt.MustExpand(").Append(GoStringLiteral(param.Value)).Append(", P, I, nil)}");
        }
        sb.Append("));");

        // Tasks that take ItemBag/PropertyBag come in two flavors: with or
        // without <Output/> bindings. If there are outputs we construct an
        // *OutputList literal; otherwise pass nil. PropertyBag is always
        // available so property-bound outputs can be written back to P.
        if (TaskNeedsItemBag(task.Name)) {
            sb.Length -= 2;
            sb.Append(", ").Append(EmitTaskOutputList(task)).Append(", I, P);");
        }
        sb.AppendLine(" err != nil { rt.GetErrorList().Add(\"" + EscapeForGo(target.Name) + "\", err) }");

        if (!string.IsNullOrWhiteSpace(task.Condition)) {
            sb.AppendLine("\t}");
        }
    }

    // EmitBatchedLocalTaskCall emits the per-source-item loop variant of a
    // local-task call. The classifier guaranteed that no <Output/> bindings
    // exist (per-iter accumulation isn't modelled) and that taskSrcList is
    // the single qualifier shared by every batched ref in the condition or
    // any parameter value.
    static void EmitBatchedLocalTaskCall(StringBuilder sb, ProjectTargetInstance target, ProjectTaskInstance task, string fn, string srcList) {
        sb.Append("\t{").AppendLine();
        sb.Append("\t\tfor _, src := range I.Get(").Append(GoStringLiteral(srcList)).AppendLine(") {");
        sb.Append("\t\t\tmeta := rt.ItemBatchMeta(src)").AppendLine();
        sb.AppendLine("\t\t\t_ = meta // may be unused if every ref is qualified-only");
        var bodyIndent = "\t\t\t";
        if (!string.IsNullOrWhiteSpace(task.Condition)) {
            sb.Append(bodyIndent).Append("if !rt.MustEvalConditionWithMeta(").Append(GoStringLiteral(task.Condition)).AppendLine(", P, I, meta) { continue }");
        }
        sb.Append(bodyIndent).Append("if err := rt.").Append(fn).Append("(rt.NewParamList(");
        var first = true;
        foreach (var param in task.Parameters) {
            if (!first) sb.Append(", ");
            first = false;
            sb.Append("rt.Param{Key: ").Append(GoStringLiteral(param.Key))
              .Append(", Value: rt.MustExpand(").Append(GoStringLiteral(param.Value)).Append(", P, I, meta)}");
        }
        sb.Append("));");
        if (TaskNeedsItemBag(task.Name)) {
            sb.Length -= 2;
            sb.Append(", nil, I, P);");
        }
        sb.AppendLine(" err != nil { rt.GetErrorList().Add(\"" + EscapeForGo(target.Name) + "\", err) }");
        sb.Append("\t\t}").AppendLine();
        sb.Append("\t}").AppendLine();
    }

    // EmitTaskOutputList emits the second argument to a task helper —
    // either `nil` (no <Output/> children) or `rt.NewOutputList(rt.Output{...})`
    // populated with the task's output bindings (both item and property).
    static string EmitTaskOutputList(ProjectTaskInstance task) {
        if (task.Outputs.Count == 0) return "nil";
        var sb = new StringBuilder();
        sb.Append("rt.NewOutputList(");
        var first = true;
        foreach (var o in task.Outputs) {
            if (!first) sb.Append(", ");
            first = false;
            switch (o) {
                case ProjectTaskOutputItemInstance oi:
                    sb.Append("rt.Output{Key: ").Append(GoStringLiteral(oi.TaskParameter))
                      .Append(", ItemName: ").Append(GoStringLiteral(oi.ItemType))
                      .Append("}");
                    break;
                case ProjectTaskOutputPropertyInstance op:
                    sb.Append("rt.Output{Key: ").Append(GoStringLiteral(op.TaskParameter))
                      .Append(", PropertyName: ").Append(GoStringLiteral(op.PropertyName))
                      .Append("}");
                    break;
                default:
                    // Unknown output binding type — emit a dummy entry so the
                    // generated source still compiles but the runtime will
                    // ignore it.
                    sb.Append("rt.Output{}");
                    break;
            }
        }
        sb.Append(")");
        return sb.ToString();
    }

    // EmitCallTargetTask emits a `<CallTarget Targets="..." />` task as a
    // runtime loop that splits the expanded Targets attribute and dispatches
    // each non-empty name through dispatchTarget. Mirrors the dynamic-
    // DependsOnTargets emission. RunEachTargetSeparately and ContinueOnError
    // are ignored (single-pass sequential dispatch — the runtime currently
    // panics on any task error anyway).
    static void EmitCallTargetTask(StringBuilder sb, ProjectTargetInstance target, ProjectTaskInstance task) {
        if (!string.IsNullOrWhiteSpace(task.Condition)) {
            sb.Append("\tif rt.MustEvalCondition(").Append(GoStringLiteral(task.Condition)).AppendLine(", P, I) {");
        }
        var targetsAttr = task.Parameters.TryGetValue("Targets", out var t) ? t : "";
        sb.Append("\t\tfor _, _ct := range rt.SplitSemicolon(rt.MustExpand(")
          .Append(GoStringLiteral(targetsAttr)).AppendLine(", P, I, nil)) {");
        sb.AppendLine("\t\t\tif _ct == \"\" { continue }");
        sb.Append("\t\t\tif !dispatchTarget(_ct) { panic(\"CallTarget: unknown target referenced by ")
          .Append(EscapeForGo(target.Name)).AppendLine("\") }");
        sb.AppendLine("\t\t}");
        if (!string.IsNullOrWhiteSpace(task.Condition)) {
            sb.AppendLine("\t}");
        }
    }

    // ClassifyJoinItemsTask returns null if the JoinItems task can be
    // emitted directly, or a short reason string otherwise.
    //
    // Supported shape:
    //   <JoinItems Left="@(L)" Right="@(R)" or Right="$(prop)"
    //              LeftKey="..." RightKey="..."
    //              LeftMetadata="..." RightMetadata="..."
    //              ItemSpecToUse="">
    //     <Output TaskParameter="JoinResult" ItemName="OutName"/>
    //   </JoinItems>
    //
    // All scalar params must be simple expressions (no batching, no
    // transforms inside `@()`). Output binding must be a single
    // `<Output TaskParameter="JoinResult" ItemName="..."/>` (the only
    // output JoinItems exposes); PropertyName binding is rejected because
    // JoinResult is item-typed.
    static string? ClassifyJoinItemsTask(ProjectTaskInstance task) {
        if (!IsSimpleConditionTemplate(task.Condition)) return "complex-task-condition";
        if (ContainsBatching(task.Condition)) return "task-batching";

        // Left is required and must be an item-list reference `@(X)`.
        if (!task.Parameters.TryGetValue("Left", out var left) || string.IsNullOrWhiteSpace(left))
            return "complex-task-param:JoinItems.Left";
        if (TryGetSimpleItemListRef(left) == null) return "complex-task-param:JoinItems.Left";
        if (ContainsBatching(left)) return "task-batching";

        // Right may be `@(X)` (item-list) OR a simple expression that
        // expands to a `;`-separated identity string (e.g. `$(prop)`).
        if (!task.Parameters.TryGetValue("Right", out var right) || string.IsNullOrWhiteSpace(right))
            return "complex-task-param:JoinItems.Right";
        var rightIsItemList = TryGetSimpleItemListRef(right) != null;
        if (!rightIsItemList && !IsSimpleExpressionTemplate(right))
            return "complex-task-param:JoinItems.Right";
        if (ContainsBatching(right)) return "task-batching";

        foreach (var key in new[] { "LeftKey", "RightKey", "LeftMetadata", "RightMetadata", "ItemSpecToUse" }) {
            if (!task.Parameters.TryGetValue(key, out var val) || val == null) continue;
            if (!IsSimpleExpressionTemplate(val)) return "complex-task-param:JoinItems." + key;
            if (ContainsBatching(val)) return "task-batching";
        }

        if (task.Outputs.Count == 0) return "complex-task-param:JoinItems.NoOutput";
        if (task.Outputs.Count > 1) return "complex-task-param:JoinItems.MultipleOutputs";
        if (task.Outputs[0] is not ProjectTaskOutputItemInstance oi)
            return "complex-task-param:JoinItems.OutputNotItem";
        if (!string.Equals(oi.TaskParameter, "JoinResult", StringComparison.OrdinalIgnoreCase))
            return "complex-task-param:JoinItems.OutputParam";
        if (!IsSimpleIdentifierName(oi.ItemType))
            return "complex-task-param:JoinItems.OutputItemType";
        return null;
    }

    // EmitJoinItemsTask emits a typed JoinItems call. Left and Right are
    // materialized as []*Item slices (looked up via I.Get for @() refs,
    // built from a `;`-separated identity string via rt.ItemsFromIdentities
    // for property-sourced sides). The result is bound to the single
    // `<Output ItemName="OutName"/>` via I.AppendTo.
    static void EmitJoinItemsTask(StringBuilder sb, ProjectTargetInstance target, ProjectTaskInstance task) {
        var oi = (ProjectTaskOutputItemInstance)task.Outputs[0];
        var outName = oi.ItemType;
        var hasCond = !string.IsNullOrWhiteSpace(task.Condition);

        sb.Append("\t{").AppendLine();
        var indent = "\t\t";
        if (hasCond) {
            sb.Append(indent).Append("if rt.MustEvalCondition(").Append(GoStringLiteral(task.Condition)).AppendLine(", P, I) {");
            indent = "\t\t\t";
        }

        var leftVal = task.Parameters["Left"];
        var rightVal = task.Parameters["Right"];
        sb.Append(indent).Append("_jiLeft := ").Append(EmitJoinItemsSide(leftVal)).AppendLine();
        sb.Append(indent).Append("_jiRight := ").Append(EmitJoinItemsSide(rightVal)).AppendLine();
        sb.Append(indent).AppendLine("_jiArgs := rt.JoinItemsArgs{");
        sb.Append(indent).AppendLine("\tLeft:  _jiLeft,");
        sb.Append(indent).AppendLine("\tRight: _jiRight,");
        EmitJoinItemsStringField(sb, indent, "LeftKey", task);
        EmitJoinItemsStringField(sb, indent, "RightKey", task);
        EmitJoinItemsStringField(sb, indent, "LeftMetadata", task);
        EmitJoinItemsStringField(sb, indent, "RightMetadata", task);
        EmitJoinItemsStringField(sb, indent, "ItemSpecToUse", task);
        sb.Append(indent).AppendLine("}");
        sb.Append(indent).Append("_jiOut := rt.NewOutputList(rt.Output{Key: \"JoinResult\", ItemName: ")
          .Append(GoStringLiteral(outName)).AppendLine("})");
        sb.Append(indent).AppendLine("if err := rt.JoinItems(_jiArgs, _jiOut, I, P); err != nil {");
        sb.Append(indent).Append("\trt.GetErrorList().Add(\"").Append(EscapeForGo(target.Name)).AppendLine("\", err)");
        sb.Append(indent).AppendLine("}");
        if (hasCond) {
            sb.Append("\t\t}").AppendLine();
        }
        sb.Append("\t}").AppendLine();
    }

    // EmitJoinItemsSide returns a Go expression that yields []*Item for a
    // JoinItems Left/Right parameter. `@(X)` becomes `I.Get("X")`; other
    // simple expressions are expanded then split into identity-only items
    // via rt.ItemsFromIdentities.
    static string EmitJoinItemsSide(string val) {
        var listName = TryGetSimpleItemListRef(val);
        if (listName != null) {
            return "I.Get(" + GoStringLiteral(listName) + ")";
        }
        return "rt.ItemsFromIdentities(rt.MustExpand(" + GoStringLiteral(val) + ", P, I, nil))";
    }

    static void EmitJoinItemsStringField(StringBuilder sb, string indent, string key, ProjectTaskInstance task) {
        var val = task.Parameters.TryGetValue(key, out var v) ? v : "";
        if (string.IsNullOrEmpty(val)) return;
        sb.Append(indent).Append("\t").Append(key).Append(": rt.MustExpand(")
          .Append(GoStringLiteral(val)).AppendLine(", P, I, nil),");
    }

    // TryGetSimpleItemListRef returns the item-list name if `val` is exactly
    // `@(SimpleIdent)` (possibly with surrounding whitespace), otherwise
    // null. Used by the JoinItems classifier + emitter to recognize the
    // `Left="@(X)"` shape without engaging the general expression path.
    static string? TryGetSimpleItemListRef(string? val) {
        if (string.IsNullOrEmpty(val)) return null;
        var s = val.Trim();
        if (s.Length < 4 || s[0] != '@' || s[1] != '(' || s[s.Length - 1] != ')') return null;
        var inner = s.Substring(2, s.Length - 3).Trim();
        return IsSimpleIdentifierName(inner) ? inner : null;
    }

    // ClassifyTarget returns null if the target can be emitted with a real
    // body, or a short reason string otherwise.
    static string? ClassifyTarget(ProjectTargetInstance target) {
        if (ContainsBatching(target.Inputs) || ContainsBatching(target.Outputs)) {
            return "target-batching";
        }
        if (!IsSimpleExpressionTemplate(target.Inputs)) return "target-inputs-complex";
        if (!IsSimpleExpressionTemplate(target.Outputs)) return "target-outputs-complex";
        if (HasDynamicExtenderAttr(target.BeforeTargets) || HasDynamicExtenderAttr(target.AfterTargets)) {
            // Dynamic Before/AfterTargets ($/@/% in the attribute) would require
            // runtime extender registration, which Phase E doesn't model.
            return "before-after-dynamic";
        }
        if (!string.IsNullOrWhiteSpace(target.DependsOnTargets)) {
            var (ok, reason) = IsSimpleDependsOnTargetsTemplate(target.DependsOnTargets);
            if (!ok) return reason!;
        }
        if (!IsSimpleConditionTemplate(target.Condition)) {
            return "complex-target-condition";
        }
        foreach (var child in target.Children) {
            switch (child) {
                case ProjectTaskInstance task:
                    if (string.Equals(task.Name, "CallTarget", StringComparison.OrdinalIgnoreCase)) {
                        // CallTarget has no <Output/> bindings worth modelling;
                        // its only effect is the side-effect of dispatching
                        // the listed targets. We accept any condition that
                        // passes the standard simple-condition check, and any
                        // Targets expression that passes IsSimpleExpression.
                        if (!IsSimpleConditionTemplate(task.Condition)) return "complex-task-condition";
                        if (task.Parameters.TryGetValue("Targets", out var ctTargets)) {
                            if (!IsSimpleExpressionTemplate(ctTargets)) return "complex-task-param:CallTarget.Targets";
                            if (ContainsBatching(ctTargets)) return "task-batching";
                        }
                        break;
                    }
                    if (string.Equals(task.Name, "JoinItems", StringComparison.OrdinalIgnoreCase)) {
                        // JoinItems uses a dedicated typed call path (the
                        // standard ParamList path can't preserve Left/Right
                        // metadata). Validate the supported shape here.
                        var jiReason = ClassifyJoinItemsTask(task);
                        if (jiReason != null) return jiReason;
                        break;
                    }
                    if (LocalTaskGoFunc(task.Name) == null) return "task:" + task.Name;
                    if (task.Outputs.Count > 0) {
                        // Both item-list and property outputs are wired
                        // through OutputList in the runtime helpers. Reject
                        // any task that isn't on the OutputCapableLocalTasks
                        // whitelist, and any output binding whose target
                        // ItemName/PropertyName isn't a simple identifier.
                        if (!OutputCapableLocalTasks.Contains(task.Name)) return "task-has-outputs:" + task.Name;
                        foreach (var output in task.Outputs) {
                            switch (output) {
                                case ProjectTaskOutputItemInstance oi:
                                    if (!IsSimpleIdentifierName(oi.ItemType)) return "task-output-complex-itemtype:" + task.Name;
                                    break;
                                case ProjectTaskOutputPropertyInstance op:
                                    if (!IsSimpleIdentifierName(op.PropertyName)) return "task-output-complex-propname:" + task.Name;
                                    break;
                                default:
                                    return "task-output-unknown:" + task.Name;
                            }
                        }
                    }
                    {
                        // Detect task-level batching: when condition or any
                        // parameter value contains %() outside `@()`, MSBuild
                        // runs the task once per unique combination of the
                        // referenced metadata values. We accept the simple
                        // single-source-list form (all qualified refs share
                        // one qualifier).
                        var taskSrcList = ComputeTaskBatchSrcList(task);
                        var hasBatching = taskSrcList != null
                            || ContainsBatching(task.Condition)
                            || task.Parameters.Any(p => ContainsBatching(p.Value));
                        if (hasBatching && taskSrcList == null) return "task-batching";
                        // Batched tasks with <Output/> bindings would need
                        // per-iter output accumulation (each batch appends to
                        // the output list / overwrites the output property).
                        // For now, reject so the wrong-output case is loud.
                        if (taskSrcList != null && task.Outputs.Count > 0) return "task-batching-with-outputs";
                        if (!IsSimpleConditionTemplate(task.Condition, taskSrcList)) return "complex-task-condition";
                        foreach (var p in task.Parameters) {
                            if (!IsSimpleExpressionTemplate(p.Value, taskSrcList)) return "complex-task-param:" + task.Name + "." + p.Key;
                        }
                    }
                    break;
                case ProjectPropertyGroupTaskInstance pg:
                    var pgReason = ClassifyPropertyGroup(pg);
                    if (pgReason != null) return pgReason;
                    break;
                case ProjectItemGroupTaskInstance ig:
                    var igReason = ClassifyItemGroup(ig);
                    if (igReason != null) return igReason;
                    break;
                case ProjectOnErrorInstance:
                    return "on-error";
                default:
                    return "unknown-target-child";
            }
        }
        return null;
    }

    static string? ClassifyPropertyGroup(ProjectPropertyGroupTaskInstance pg) {
        if (!IsSimpleConditionTemplate(pg.Condition)) return "pg-complex-condition";
        foreach (var prop in pg.Properties) {
            if (ContainsBatching(prop.Value)) return "pg-batching";
            if (ContainsBatching(prop.Condition)) return "pg-batching";
            if (!IsSimpleConditionTemplate(prop.Condition)) return "pg-complex-prop-condition";
            if (!IsSimpleExpressionTemplate(prop.Value)) return "pg-complex-prop-value";
            if (!IsSimpleIdentifierName(prop.Name)) return "pg-complex-prop-name";
        }
        return null;
    }

    // TryGetTransformIncludeSrcList returns the source item-list name when
    // include is exactly `@(SimpleIdent->'tpl')` (no chained methods, no
    // sep). The transform's per-item iteration drives batching when the
    // ItemGroup also has `%()` references in cond/meta. Returns null for
    // any other shape (including chained transforms and Distinct(); those
    // remain ig-include-complex).
    static string? TryGetTransformIncludeSrcList(string include) {
        if (string.IsNullOrEmpty(include)) return null;
        var trimmed = include.Trim();
        if (!trimmed.StartsWith("@(", StringComparison.Ordinal)) return null;
        if (!trimmed.EndsWith(")", StringComparison.Ordinal)) return null;
        var inner = trimmed.Substring(2, trimmed.Length - 3);
        var arrow = inner.IndexOf("->", StringComparison.Ordinal);
        if (arrow < 0) return null;
        var name = inner.Substring(0, arrow).Trim();
        if (!IsSimpleIdentifierName(name)) return null;
        var rhs = inner.Substring(arrow + 2).TrimStart();
        if (rhs.Length < 2) return null;
        var q = rhs[0];
        if (q != '\'' && q != '"') return null;
        if (!IsSimpleTransformRhs(rhs)) return null;
        return name;
    }

    // TryGetTransformIncludeTemplate returns the template string from
    // `@(SimpleIdent->'tpl')` for use in per-iteration MustExpand. Returns
    // null for any other shape. Caller is responsible for verifying the
    // include is a transform-include via TryGetTransformIncludeSrcList
    // first; this helper is the second step for the emitter only.
    static string? TryGetTransformIncludeTemplate(string include) {
        if (string.IsNullOrEmpty(include)) return null;
        var trimmed = include.Trim();
        if (!trimmed.StartsWith("@(", StringComparison.Ordinal)) return null;
        if (!trimmed.EndsWith(")", StringComparison.Ordinal)) return null;
        var inner = trimmed.Substring(2, trimmed.Length - 3);
        var arrow = inner.IndexOf("->", StringComparison.Ordinal);
        if (arrow < 0) return null;
        var rhs = inner.Substring(arrow + 2).TrimStart();
        if (rhs.Length < 2) return null;
        var q = rhs[0];
        if (q != '\'' && q != '"') return null;
        var end = rhs.IndexOf(q, 1);
        if (end < 0) return null;
        return rhs.Substring(1, end - 1);
    }

    static string? ClassifyItemGroup(ProjectItemGroupTaskInstance ig) {
        if (!IsSimpleConditionTemplate(ig.Condition)) return "ig-complex-condition";
        foreach (var item in ig.Items) {
            if (!IsSimpleIdentifierName(item.ItemType)) return "ig-complex-item-type";

            var rawInc = item.Include ?? "";
            var rawRem = item.Remove ?? "";

            // Determine the batched source list once. Order of precedence:
            //   1. Include / Remove "@(SrcList)" literal — the cleanest signal.
            //   2. No Include/Remove → modify-meta, srcList = ItemType.
            //   3. Fall back to a single qualifier extracted from the
            //      condition or metadata (literal Include with batched
            //      `%(L.M)` references, e.g. AssemblyAttribute / InternalsVisibleTo).
            string? srcList = null;
            if (rawInc.Length > 0 && ClassifyItemIncludeSpec(rawInc) == ItemIncludeKind.ItemListCopy) {
                var trimmed = rawInc.Trim();
                var ident = trimmed.Substring(2, trimmed.Length - 3).Trim();
                if (IsSimpleIdentifierName(ident)) srcList = ident;
            } else if (rawInc.Length == 0 && rawRem.Length > 0
                       && ClassifyItemIncludeSpec(rawRem) == ItemIncludeKind.ItemListCopy) {
                var trimmed = rawRem.Trim();
                var ident = trimmed.Substring(2, trimmed.Length - 3).Trim();
                if (IsSimpleIdentifierName(ident)) srcList = ident;
            } else if (rawInc.Length == 0 && rawRem.Length == 0) {
                srcList = item.ItemType;
            } else if (rawInc.Length > 0) {
                // Transform include `@(SrcList->'tpl')` — SrcList drives the
                // per-item batched iteration when cond/meta reference `%()`.
                srcList = TryGetTransformIncludeSrcList(rawInc);
            }
            if (srcList == null) {
                var fromCond = ExtractSingleBatchQualifier(item.Condition ?? "");
                string? fromMeta = null;
                foreach (var meta in item.Metadata) {
                    fromMeta ??= ExtractSingleBatchQualifier(meta.Value ?? "");
                    fromMeta ??= ExtractSingleBatchQualifier(meta.Condition ?? "");
                }
                if (fromCond != null && fromMeta != null
                    && !string.Equals(fromCond, fromMeta, StringComparison.OrdinalIgnoreCase)) {
                    // Conflicting qualifiers across cond and meta would require
                    // cross-list batching — not supported.
                    return "ig-meta-batching";
                }
                srcList = fromCond ?? fromMeta;
            }

            // Validate item condition. Without a srcList, %()-bearing conditions
            // fall through as ig-complex-item-condition; with one, batched
            // operands are allowed.
            if (!IsSimpleConditionTemplate(item.Condition, srcList)) return "ig-complex-item-condition";

            // Reject advanced item attributes that we don't model.
            if (!string.IsNullOrEmpty(item.Exclude)) {
                // Exclude must be an expression the runtime can evaluate
                // (no batching, no transforms outside @() — same rules as
                // Include/Remove). The emitter expands it once at runtime
                // and filters the include loop against the resulting set.
                if (ContainsBatching(item.Exclude)) return "ig-exclude-batching";
                if (!IsSimpleExpressionTemplate(item.Exclude)) return "ig-exclude-complex";
                // Exclude semantics only make sense with an Include. MSBuild
                // tolerates the lone form but it's a no-op; reject so silent
                // no-ops don't slip through.
                if (string.IsNullOrEmpty(item.Include)) return "ig-exclude-without-include";
            }
            if (!string.IsNullOrEmpty(item.KeepDuplicates)) return "ig-keep-duplicates-not-supported";
            if (!string.IsNullOrEmpty(item.KeepMetadata)) return "ig-keep-metadata-not-supported";
            if (!string.IsNullOrEmpty(item.RemoveMetadata)) return "ig-remove-metadata-not-supported";
            if (!string.IsNullOrEmpty(item.MatchOnMetadata)) return "ig-match-metadata-not-supported";

            var include = item.Include ?? "";
            var remove = item.Remove ?? "";
            if (include.Length > 0 && remove.Length > 0) return "ig-include-and-remove";
            if (include.Length == 0 && remove.Length == 0) {
                // <ItemGroup><X><Meta>v</Meta></X></ItemGroup> with no
                // Include/Remove is a "modify metadata of all existing items
                // of this type" operation (MSBuild ItemGroupIntrinsicTask.
                // ExecuteModify). Accept it if there's metadata to apply;
                // truly empty items (no metadata either) are still rejected.
                if (item.Metadata.Count == 0) return "ig-empty-include-remove";
            } else {
                var spec = include.Length > 0 ? include : remove;
                if (ContainsBatching(spec)) {
                    // Batched Include/Remove value (e.g. literal text with
                    // `%(L.M)`). Only accept when srcList is known and the
                    // spec validates against it. Transforms `@(X->'%(F)')`
                    // are still ig-include-complex.
                    if (srcList == null) return "ig-spec-batching";
                    if (!IsSimpleExpressionTemplate(spec)) return "ig-spec-batching";
                    if (!ValidateBatchMetaRefsInString(spec, srcList)) return "ig-spec-batching";
                }
                if (ContainsGlobChar(spec)) return "ig-spec-glob-not-supported";
                if (include.Length > 0) {
                    var includeKind = ClassifyItemIncludeSpec(include);
                    if (includeKind == ItemIncludeKind.Unsupported) return "ig-include-complex";
                } else {
                    // Remove="..." path: any expression that IsSimpleExpression
                    // can handle is fine here, including @(SomeItemList). The
                    // emitter passes Remove through rt.MustExpand which already
                    // joins @() lists by identity and SplitSemicolon-splits the
                    // result for per-identity removal.
                    if (!IsSimpleExpressionTemplate(remove)) return "ig-remove-complex";
                }
            }

            foreach (var meta in item.Metadata) {
                if (ContainsBatching(meta.Value)) {
                    if (srcList == null) return "ig-meta-batching";
                    if (!IsSimpleExpressionTemplate(meta.Value, srcList)) return "ig-complex-meta-value";
                    if (!ValidateBatchMetaRefsInString(meta.Value, srcList)) return "ig-meta-batching";
                } else if (!IsSimpleExpressionTemplate(meta.Value)) {
                    return "ig-complex-meta-value";
                }
                if (!IsSimpleConditionTemplate(meta.Condition, srcList)) return "ig-complex-meta-condition";
                if (!IsSimpleIdentifierName(meta.Name)) return "ig-complex-meta-name";
            }
        }
        return null;
    }

    // DescribeRejection returns a human-readable hint about why a given target
    // was classified as unsupported. Only used when BSHARP_DEBUG_REJECTIONS is
    // set, to support pattern surveying for the next round of emitter work.
    static string? DescribeRejection(ProjectTargetInstance target, string reason) {
        switch (reason) {
            case "complex-target-condition":
                return target.Condition;
            case "complex-task-condition":
                foreach (var child in target.Children) {
                    if (child is ProjectTaskInstance task && !IsSimpleConditionTemplate(task.Condition)) {
                        return $"{task.Name}: {task.Condition}";
                    }
                }
                return null;
            case "pg-complex-prop-condition":
                foreach (var child in target.Children) {
                    if (child is ProjectPropertyGroupTaskInstance pg) {
                        foreach (var prop in pg.Properties) {
                            if (!IsSimpleConditionTemplate(prop.Condition)) {
                                return $"{prop.Name}: {prop.Condition}";
                            }
                        }
                    }
                }
                return null;
            case "ig-complex-item-condition":
                foreach (var child in target.Children) {
                    if (child is ProjectItemGroupTaskInstance ig) {
                        foreach (var item in ig.Items) {
                            if (!IsSimpleConditionTemplate(item.Condition)) {
                                return $"{item.ItemType}: {item.Condition}";
                            }
                        }
                    }
                }
                return null;
            case "ig-include-complex":
                foreach (var child in target.Children) {
                    if (child is ProjectItemGroupTaskInstance ig) {
                        foreach (var item in ig.Items) {
                            if (!string.IsNullOrEmpty(item.Include) &&
                                ClassifyItemIncludeSpec(item.Include) == ItemIncludeKind.Unsupported) {
                                return $"{item.ItemType}: Include='{item.Include}'";
                            }
                        }
                    }
                }
                return null;
            case "ig-meta-batching":
                foreach (var child in target.Children) {
                    if (child is ProjectItemGroupTaskInstance ig) {
                        foreach (var item in ig.Items) {
                            foreach (var meta in item.Metadata) {
                                if (ContainsBatching(meta.Value)) {
                                    return $"{item.ItemType}/{meta.Name}: {meta.Value}";
                                }
                            }
                        }
                    }
                }
                return null;
            case "ig-empty-include-remove":
                foreach (var child in target.Children) {
                    if (child is ProjectItemGroupTaskInstance ig) {
                        foreach (var item in ig.Items) {
                            if (string.IsNullOrEmpty(item.Include) && string.IsNullOrEmpty(item.Remove)) {
                                var metaList = string.Join(",", item.Metadata.Select(m => m.Name));
                                return $"{item.ItemType}: meta=[{metaList}]";
                            }
                        }
                    }
                }
                return null;
            default:
                return null;
        }
    }

    // so the emitter can pick the right runtime call:
    //   - Literal: no @() refs at all; expand + split + new items
    //   - ItemListCopy: exactly one @(SimpleType) reference; clone source items
    //   - ItemListFilter: @(SrcList->WithMetadataValue('M', 'V')); clone
    //     matching source items, preserving all metadata
    //   - Unsupported: anything else (mixed, transforms, etc.)
    enum ItemIncludeKind { Literal, ItemListCopy, ItemListFilter, Unsupported }

    // ItemListFilterSpec captures the structured form of an ItemListFilter
    // include, recovered from re-parsing the include in EmitItemGroupChild.
    sealed record ItemListFilterSpec(string SourceItemType, string MetaName, string ValueTemplate);

    static ItemIncludeKind ClassifyItemIncludeSpec(string include) {
        if (string.IsNullOrEmpty(include)) return ItemIncludeKind.Literal;
        var trimmed = include.Trim();
        // Exactly @(SimpleIdent) — fast path that preserves source-item
        // metadata via Item.Clone (Literal only carries Identity).
        if (trimmed.StartsWith("@(", StringComparison.Ordinal) && trimmed.EndsWith(")", StringComparison.Ordinal)) {
            var inner = trimmed.Substring(2, trimmed.Length - 3);
            if (!inner.Contains("->", StringComparison.Ordinal) && !inner.Contains(",", StringComparison.Ordinal)
                && IsSimpleIdentifierName(inner.Trim())) {
                return ItemIncludeKind.ItemListCopy;
            }
            // @(SrcList->WithMetadataValue('M', 'V')) — predicate filter that
            // preserves source metadata. We detect it here (BEFORE the
            // string-joined transform fallback below) so the emitter can
            // produce a typed Item.Clone loop instead of dropping metadata.
            if (TryParseWithMetadataValueInclude(inner, out _)) {
                return ItemIncludeKind.ItemListFilter;
            }
            // Single @() but not a simple ident — fall through to Literal
            // evaluation below if IsSimpleExpressionTemplate accepts it
            // (e.g. transforms `@(X->'tpl')` produce `;`-joined identities).
        }
        // Any spec the expression evaluator can fully handle becomes a
        // Literal: evaluate at runtime via MustExpand, split on `;`, and
        // create new items. This covers literal text, plain `@(X)` mixed
        // with literals (e.g. `@(A);foo;@(B)`), item transforms
        // `@(X->'template')`, and property functions.
        if (IsSimpleExpressionTemplate(include)) return ItemIncludeKind.Literal;
        return ItemIncludeKind.Unsupported;
    }

    // TryParseWithMetadataValueInclude recognizes `Name->WithMetadataValue('M', 'V')`
    // (the inner of `@(...)`) and returns the source item-list name, the
    // metadata key, and the value template. The value template may freely
    // contain `$(SimpleProp)` expansions which are evaluated at emit-time
    // runtime via MustExpand. Returns false for any other shape.
    static bool TryParseWithMetadataValueInclude(string inner, out ItemListFilterSpec? spec) {
        spec = null;
        var arrow = inner.IndexOf("->", StringComparison.Ordinal);
        if (arrow < 0) return false;
        var name = inner.Substring(0, arrow).Trim();
        if (!IsSimpleIdentifierName(name)) return false;
        var rhs = inner.Substring(arrow + 2).TrimStart();
        const string prefix = "WithMetadataValue(";
        if (!rhs.StartsWith(prefix, StringComparison.OrdinalIgnoreCase)) return false;
        if (!rhs.EndsWith(")", StringComparison.Ordinal)) return false;
        var argsSrc = rhs.Substring(prefix.Length, rhs.Length - prefix.Length - 1);
        var parts = SplitArgsQuoteAware(argsSrc);
        if (parts.Length != 2) return false;
        string? Unquote(string raw) {
            var s = raw.Trim();
            if (s.Length < 2) return null;
            var q = s[0];
            if ((q != '\'' && q != '"') || s[s.Length - 1] != q) return null;
            return s.Substring(1, s.Length - 2);
        }
        var metaName = Unquote(parts[0]);
        var valueTpl = Unquote(parts[1]);
        if (metaName == null || valueTpl == null) return false;
        if (string.IsNullOrEmpty(metaName)) return false;
        // The metadata KEY must be a literal identifier — no expansions —
        // because the runtime calls GetMetadata(metaName) directly. The
        // VALUE template may contain `$(SimpleProp)` so it's validated via
        // the literal-expansion checker (which already rejects `@()` and
        // `%(...)` since neither is meaningful in this context).
        foreach (var ch in metaName) {
            if (!(char.IsLetterOrDigit(ch) || ch == '_' || ch == '-')) return false;
        }
        if (!AreSimpleExpansionsOnly(valueTpl)) return false;
        spec = new ItemListFilterSpec(name, metaName, valueTpl);
        return true;
    }

    static bool IsSimpleIdentifierName(string? name) {
        if (string.IsNullOrEmpty(name)) return false;
        foreach (var c in name) {
            if (!(char.IsLetterOrDigit(c) || c == '_' || c == '-')) return false;
        }
        return true;
    }

    // Returns true if `inner` (the body of an @(...) reference, without the
    // surrounding parens) is in a shape the runtime can evaluate:
    //   - "Name"                                       — simple identifier
    //   - "Name, 'sep'"                                — identifier with explicit separator
    //   - "Name->Count()"                              — count intrinsic
    //   - "Name->AnyHaveMetadataValue('m', 'v')"       — metadata predicate
    // Anything else (transforms returning items, WithMetadataValue,
    // chained calls, batching `%()` refs, etc.) is rejected so the codegen
    // + classifier never produce silently-wrong output.
    static bool IsSimpleItemRefInner(string inner) {
        var arrow = inner.IndexOf("->", StringComparison.Ordinal);
        if (arrow < 0) {
            // Plain @(X) or @(X, 'sep') — `%()` inside is meaningless and
            // would silently expand to "" outside a transform context.
            if (inner.Contains("%(", StringComparison.Ordinal)) return false;
            var parts = SplitArgsQuoteAware(inner);
            if (parts.Length == 0) return false;
            if (!IsSimpleIdentifierName(parts[0].Trim())) return false;
            if (parts.Length == 1) return true;
            if (parts.Length != 2) return false;
            var sep = parts[1].Trim();
            if (sep.Length < 2) return false;
            var q = sep[0];
            return (q == '\'' || q == '"') && sep[sep.Length - 1] == q;
        }
        var name = inner.Substring(0, arrow).Trim();
        var rhs = inner.Substring(arrow + 2).Trim();
        if (!IsSimpleIdentifierName(name)) return false;
        // Item transform `@(X->'template'[, 'sep'])` — RHS starts with a
        // quote. The template may contain `%()` (the whole point of a
        // transform) but only simple metadata refs are accepted.
        if (rhs.Length > 0 && (rhs[0] == '\'' || rhs[0] == '"')) {
            return IsSimpleTransformRhs(rhs);
        }
        // Count() — no args.
        if (string.Equals(rhs, "Count()", StringComparison.OrdinalIgnoreCase)) return true;
        // AnyHaveMetadataValue('MetaName', 'MetaValue') — two quoted args. The
        // arg values may contain $() expansions which the runtime expands; we
        // only validate the surface shape (quote balance + no nested @() /
        // %() / chained calls).
        const string anyPrefix = "AnyHaveMetadataValue(";
        if (rhs.StartsWith(anyPrefix, StringComparison.OrdinalIgnoreCase) && rhs.EndsWith(")", StringComparison.Ordinal)) {
            var argsSrc = rhs.Substring(anyPrefix.Length, rhs.Length - anyPrefix.Length - 1);
            if (argsSrc.Contains("@(", StringComparison.Ordinal)) return false;
            if (argsSrc.Contains("%(", StringComparison.Ordinal)) return false;
            // The args themselves must be exactly two quoted strings separated
            // by a comma (with optional whitespace). Anything else is rejected.
            var argParts = SplitArgsQuoteAware(argsSrc);
            if (argParts.Length != 2) return false;
            foreach (var ap in argParts) {
                var s = ap.Trim();
                if (s.Length < 2) return false;
                var q = s[0];
                if ((q != '\'' && q != '"') || s[s.Length - 1] != q) return false;
            }
            return true;
        }
        return false;
    }

    // IsSimpleTransformRhs validates an item-transform RHS:
    //   - `'template'`
    //   - `'template', 'sep'`
    //   - `'template' -> Method(args) [ -> Method(args) ... ] [, 'sep']`
    //
    // The template may freely use `%(Meta)` / `%(ItemName.Meta)` (per-item
    // batch context), `$(P)` (validated via IsSimpleExpressionInner), and
    // `@(Y)` for nested unbatched item-list refs (validated recursively).
    // Literal text is accepted as-is.
    //
    // Chained `->Method(args)` calls use the property-function whitelist
    // (TrimStart, Replace, ToLower, etc.) and reuse the same arg validator
    // as property functions — args must be quoted-string literals (with
    // optional `$()` inside) or integer literals.
    static bool IsSimpleTransformRhs(string rhs) {
        rhs = rhs.Trim();
        if (rhs.Length < 2) return false;
        var q = rhs[0];
        if (q != '\'' && q != '"') return false;
        var end = rhs.IndexOf(q, 1);
        if (end < 0) return false;
        var template = rhs.Substring(1, end - 1);
        if (!IsSimpleTransformTemplate(template)) return false;
        var rest = rhs.Substring(end + 1).TrimStart();
        while (rest.StartsWith("->", StringComparison.Ordinal)) {
            rest = rest.Substring(2).TrimStart();
            int openIdx = rest.IndexOf('(');
            if (openIdx < 0) return false;
            var methodName = rest.Substring(0, openIdx).Trim();
            if (!IsSimpleIdentifierName(methodName)) return false;
            if (!IsKnownStringTransformMethod(methodName)) return false;
            var closeIdx = FindMatchingParenQuoteAware(rest, openIdx);
            if (closeIdx < 0) return false;
            var argsSrc = rest.Substring(openIdx + 1, closeIdx - openIdx - 1);
            if (!AreSimpleTransformMethodArgs(argsSrc)) return false;
            rest = rest.Substring(closeIdx + 1).TrimStart();
        }
        if (rest.Length == 0) return true;
        if (rest[0] != ',') return false;
        rest = rest.Substring(1).TrimStart();
        if (rest.Length < 2) return false;
        var q2 = rest[0];
        if (q2 != '\'' && q2 != '"') return false;
        var endSep = rest.IndexOf(q2, 1);
        if (endSep != rest.Length - 1) return false;
        return true;
    }

    // AreSimpleTransformMethodArgs validates the argument list of a chained
    // transform method. Each arg must be a quoted string (single or double);
    // inside the quote, only literal text and simple `$()` expansions are
    // allowed (mirrors parseTransformMethodArgs at runtime). `%()` and bare
    // unquoted args are rejected so the shape stays predictable.
    static bool AreSimpleTransformMethodArgs(string argsSrc) {
        if (string.IsNullOrWhiteSpace(argsSrc)) return true;
        var parts = SplitArgsQuoteAware(argsSrc);
        foreach (var p in parts) {
            var s = p.Trim();
            if (s.Length < 2) return false;
            var q = s[0];
            if ((q != '\'' && q != '"') || s[s.Length - 1] != q) return false;
            var inner = s.Substring(1, s.Length - 2);
            if (!AreSimpleExpansionsOnly(inner)) return false;
        }
        return true;
    }

    // IsSimpleTransformTemplate validates the template body of an item
    // transform. Walks `$(...)`, `@(...)`, `%(...)` and ensures each is a
    // simple shape; rejects anything the runtime Expand can't evaluate.
    static bool IsSimpleTransformTemplate(string template) {
        for (int i = 0; i < template.Length; i++) {
            var c = template[i];
            if (c == '$' && i + 1 < template.Length && template[i + 1] == '(') {
                var end = FindMatchingParenQuoteAware(template, i + 1);
                if (end < 0) return false;
                var inner = template.Substring(i + 2, end - i - 2);
                if (!IsSimpleExpressionInner(inner)) return false;
                i = end;
                continue;
            }
            if (c == '@' && i + 1 < template.Length && template[i + 1] == '(') {
                // Nested @(Y) within a transform template — disallow further
                // nested transforms to keep this bounded.
                var end = FindMatchingParenQuoteAware(template, i + 1);
                if (end < 0) return false;
                var inner = template.Substring(i + 2, end - i - 2);
                if (inner.Contains("->", StringComparison.Ordinal)) return false;
                if (!IsSimpleItemRefInner(inner)) return false;
                i = end;
                continue;
            }
            if (c == '%' && i + 1 < template.Length && template[i + 1] == '(') {
                var end = FindMatchingParenQuoteAware(template, i + 1);
                if (end < 0) return false;
                var inner = template.Substring(i + 2, end - i - 2).Trim();
                // Accept `Identifier` or `Item.Identifier`.
                var dot = inner.IndexOf('.');
                var name = dot >= 0 ? inner.Substring(dot + 1) : inner;
                if (dot >= 0 && !IsSimpleIdentifierName(inner.Substring(0, dot))) return false;
                if (!IsSimpleIdentifierName(name)) return false;
                i = end;
                continue;
            }
        }
        return true;
    }

    static bool ContainsGlobChar(string? s) {
        if (string.IsNullOrEmpty(s)) return false;
        // A `*` or `?` outside quotes signals a glob the emitter does not expand.
        // We don't attempt to honor quoting because $(X) values rarely embed *.
        return s.IndexOfAny(new[] { '*', '?' }) >= 0;
    }

    // LocalTaskGoFunc maps an MSBuild task name to the Go runtime helper name.
    // Returns null for tasks we don't have a local implementation for yet.
    // Matching is case-insensitive — MSBuild treats task names that way and
    // SDK sources use both "NETSdkError" and "NetSdkError" in different files.
    static readonly Dictionary<string, string> _localTaskGoFunc = new(StringComparer.OrdinalIgnoreCase) {
        { "Message", "Message" },
        { "Warning", "Warning" },
        { "Error",   "Error" },
        { "MakeDir", "MakeDir" },
        { "RemoveDir", "RemoveDir" },
        { "Touch",   "Touch" },
        { "Delete",  "Delete" },
        { "Copy",    "Copy" },
        { "WriteLinesToFile", "WriteLinesToFile" },
        { "ReadLinesFromFile", "ReadLinesFromFile" },
        { "Hash", "Hash" },
        { "ConvertToAbsolutePath", "ConvertToAbsolutePath" },
        { "RemoveDuplicates", "RemoveDuplicates" },
        { "NETSdkError", "NETSdkError" },
        { "NETSdkWarning", "NETSdkWarning" },
        { "NETSdkInformation", "NETSdkInformation" },
        { "MSBuildInternalMessage", "MSBuildInternalMessage" },
        { "AllowEmptyTelemetry", "AllowEmptyTelemetry" },
        { "CheckForDuplicateNuGetItemsTask", "CheckForDuplicateNuGetItemsTask" },
        { "Exec", "Exec" },
        { "FindUnderPath", "FindUnderPath" },
        { "JoinItems", "JoinItems" },
    };
    static string? LocalTaskGoFunc(string taskName) =>
        _localTaskGoFunc.TryGetValue(taskName, out var fn) ? fn : null;

    // TaskNeedsItemBag returns true for tasks whose Go signature has the
    // shape (ParamList, *OutputList, ItemBag, PropertyBag). The emitter
    // appends ", outputs, I, P" to the call site for these. Tasks NOT in
    // this set (Message/Warning/Error/WriteLinesToFile/NETSdk*) take only
    // ParamList.
    static readonly HashSet<string> _tasksNeedingItemBag = new(StringComparer.OrdinalIgnoreCase) {
        "MakeDir", "RemoveDir", "Touch", "Delete", "Copy",
        "ReadLinesFromFile", "Hash", "ConvertToAbsolutePath", "RemoveDuplicates",
        "CheckForDuplicateNuGetItemsTask", "Exec", "FindUnderPath",
    };
    static bool TaskNeedsItemBag(string taskName) => _tasksNeedingItemBag.Contains(taskName);

    // OutputCapableLocalTasks names the tasks whose runtime helper already
    // accepts an *OutputList and writes results into ItemBag and/or
    // PropertyBag. We wire up both <Output ItemName="..."/> and
    // <Output PropertyName="..."/> bindings for these.
    static readonly HashSet<string> OutputCapableLocalTasks = new(StringComparer.OrdinalIgnoreCase) {
        "Copy", "ReadLinesFromFile", "MakeDir", "RemoveDir", "Touch", "Delete",
        "Hash", "ConvertToAbsolutePath", "RemoveDuplicates",
        "CheckForDuplicateNuGetItemsTask", "Exec", "FindUnderPath",
    };

    // IsSimpleExpressionTemplate returns true if `template` only uses constructs
    // the runtime.Expand evaluator handles in Phase A+B+G: literals, $(X),
    // $(X.Method(args)) chains with whitelisted methods and simple args,
    // $([MSBuild]::F(args)) supported intrinsics, @(Y) (no transforms),
    // and %(Z).
    static bool IsSimpleExpressionTemplate(string? template) =>
        IsSimpleExpressionTemplate(template, allowedQualifier: null);

    // IsSimpleExpressionTemplate validates a value-context template (Include,
    // Exclude, metadata value, task parameter value, property value). When
    // `allowedQualifier` is non-null, `%(qualifier.M)` and `%(M)` references
    // are accepted both at the top level and inside intrinsic args, because
    // the emitter has classified this template as part of a batched per-item
    // iteration where a metadata bag is available at runtime.
    static bool IsSimpleExpressionTemplate(string? template, string? allowedQualifier) {
        if (string.IsNullOrEmpty(template)) return true;
        for (int i = 0; i < template.Length; i++) {
            var c = template[i];
            if (c == '$' || c == '@' || c == '%') {
                if (i + 1 >= template.Length || template[i + 1] != '(') continue;
                var end = FindMatchingParenQuoteAware(template, i + 1);
                if (end < 0) return false;
                var inner = template.Substring(i + 2, end - i - 2);
                if (c == '$') {
                    if (!IsSimpleExpressionInner(inner, allowedQualifier)) return false;
                } else if (c == '@') {
                    if (!IsSimpleItemRefInner(inner)) return false;
                } else { // '%'
                    if (allowedQualifier == null) return false;
                    if (!IsValidBatchMetaRef(inner, allowedQualifier)) return false;
                }
                i = end;
            }
        }
        return true;
    }

    // IsSimpleExpressionInner accepts either a Phase A/B property expression
    // (bare identifier or whitelisted method chain on a property) OR a Phase G
    // [TypeName]::Member(args?) call with supported type+member + simple args.
    // Mirrors what the Go runtime's Expand evaluator accepts inside `$(...)`.
    static bool IsSimpleExpressionInner(string inner) =>
        IsSimpleExpressionInner(inner, allowedQualifier: null);

    static bool IsSimpleExpressionInner(string inner, string? allowedQualifier) {
        var trimmed = inner.Trim();
        if (trimmed.Length > 0 && trimmed[0] == '[') {
            return IsSimpleIntrinsicCall(trimmed, allowedQualifier);
        }
        // Anything else containing `[` or `:` past the leading char is an
        // unsupported intrinsic or indexer construct we haven't modelled.
        if (inner.IndexOfAny(new[] { '[', ':' }) >= 0) return false;
        return IsSimplePropertyExpression(inner);
    }

    static bool IsSimpleIntrinsicCall(string s) =>
        IsSimpleIntrinsicCall(s, allowedQualifier: null);

    // IsSimpleIntrinsicCall validates the shape `[TypeName]::Member(args?)`.
    // Type+member must appear in IntrinsicMembers (mirrors the runtime
    // dispatch in EvalIntrinsic). Member may be parameterless (static
    // property like `[System.IO.Path]::DirectorySeparatorChar`).
    // When `allowedQualifier` is non-null, `%(...)` references that target
    // it are permitted inside intrinsic args (runtime threads batchMeta
    // through tryEvalIntrinsic → resolveIntrinsicArg → Expand).
    static bool IsSimpleIntrinsicCall(string s, string? allowedQualifier) {
        if (s.Length < 2 || s[0] != '[') return false;
        var closeBracket = s.IndexOf(']');
        if (closeBracket <= 1) return false;
        var typeName = s.Substring(1, closeBracket - 1).Trim();
        if (!IntrinsicMembers.ContainsKey(typeName)) return false;
        var afterBracket = s.Substring(closeBracket + 1);
        if (!afterBracket.StartsWith("::", StringComparison.Ordinal)) return false;
        var rest = afterBracket.Substring(2);
        int nameEnd = 0;
        while (nameEnd < rest.Length && (char.IsLetterOrDigit(rest[nameEnd]) || rest[nameEnd] == '_')) nameEnd++;
        if (nameEnd == 0) return false;
        var member = rest.Substring(0, nameEnd);
        var supportedMembers = IntrinsicMembers[typeName];
        var memberSpec = supportedMembers.FirstOrDefault(m => m.Name.Equals(member, StringComparison.OrdinalIgnoreCase));
        if (memberSpec.Name == null) return false;
        var tail = rest.Substring(nameEnd);
        if (tail.Length == 0) {
            // Property-style access (no parens).
            return !memberSpec.RequiresArgs;
        }
        if (tail[0] != '(') return false;
        var close = FindMatchingParenQuoteAware(tail, 0);
        if (close < 0) return false;
        if (tail.Substring(close + 1).Trim().Length != 0) return false;
        var argsStr = tail.Substring(1, close - 1);
        return AreSimpleMSBuildIntrinsicArgs(argsStr, allowedQualifier);
    }

    readonly struct IntrinsicMember {
        public string Name { get; init; }
        public bool RequiresArgs { get; init; }
    }

    // IntrinsicMembers mirrors the runtime EvalIntrinsic dispatch (see
    // msbuild_intrinsics.go). When adding a new member to the runtime,
    // add it here too. Property-style members (no parens) have
    // RequiresArgs=false.
    static readonly Dictionary<string, IntrinsicMember[]> IntrinsicMembers =
        new(StringComparer.OrdinalIgnoreCase) {
            ["MSBuild"] = new IntrinsicMember[] {
                new() { Name = "VersionEquals", RequiresArgs = true },
                new() { Name = "VersionGreaterThan", RequiresArgs = true },
                new() { Name = "VersionGreaterThanOrEquals", RequiresArgs = true },
                new() { Name = "VersionLessThan", RequiresArgs = true },
                new() { Name = "VersionLessThanOrEquals", RequiresArgs = true },
                new() { Name = "IsOSPlatform", RequiresArgs = true },
                new() { Name = "IsOsPlatform", RequiresArgs = true },
                new() { Name = "ValueOrDefault", RequiresArgs = true },
                new() { Name = "Escape", RequiresArgs = true },
                new() { Name = "EnsureTrailingSlash", RequiresArgs = true },
                new() { Name = "MakeRelative", RequiresArgs = true },
                new() { Name = "NormalizePath", RequiresArgs = true },
                new() { Name = "NormalizeDirectory", RequiresArgs = true },
                new() { Name = "DoesTaskHostExist", RequiresArgs = true },
                new() { Name = "IsTargetFrameworkCompatible", RequiresArgs = true },
            },
            ["System.IO.Path"] = new IntrinsicMember[] {
                new() { Name = "Combine", RequiresArgs = true },
                new() { Name = "GetFullPath", RequiresArgs = true },
                new() { Name = "GetFileName", RequiresArgs = true },
                new() { Name = "GetFileNameWithoutExtension", RequiresArgs = true },
                new() { Name = "GetExtension", RequiresArgs = true },
                new() { Name = "GetDirectoryName", RequiresArgs = true },
                new() { Name = "IsPathRooted", RequiresArgs = true },
                new() { Name = "ChangeExtension", RequiresArgs = true },
                new() { Name = "DirectorySeparatorChar", RequiresArgs = false },
                new() { Name = "PathSeparator", RequiresArgs = false },
                new() { Name = "AltDirectorySeparatorChar", RequiresArgs = false },
                new() { Name = "GetTempPath", RequiresArgs = false },
                new() { Name = "GetRandomFileName", RequiresArgs = false },
            },
            ["System.Text.RegularExpressions.Regex"] = new IntrinsicMember[] {
                new() { Name = "Replace", RequiresArgs = true },
                new() { Name = "IsMatch", RequiresArgs = true },
                new() { Name = "Match", RequiresArgs = true },
            },
            ["System.Guid"] = new IntrinsicMember[] {
                new() { Name = "NewGuid", RequiresArgs = true },
            },
        };

    // AreSimpleMSBuildIntrinsicArgs splits `argsStr` on top-level commas and
    // checks each argument is either a quoted string (whose interior may
    // itself contain only simple $() references), a single $(SimpleProp)
    // expansion, or a bare literal (digits/dots/identifier chars — used for
    // bare version literals like `5.0`). Anything else fails.
    static bool AreSimpleMSBuildIntrinsicArgs(string argsStr) =>
        AreSimpleMSBuildIntrinsicArgs(argsStr, allowedQualifier: null);

    static bool AreSimpleMSBuildIntrinsicArgs(string argsStr, string? allowedQualifier) {
        if (string.IsNullOrWhiteSpace(argsStr)) return true;
        var depth = 0;
        char quote = '\0';
        int start = 0;
        var parts = new List<string>();
        for (int i = 0; i < argsStr.Length; i++) {
            var c = argsStr[i];
            if (quote != '\0') {
                if (c == quote) quote = '\0';
                continue;
            }
            switch (c) {
                case '\'': case '"': quote = c; break;
                case '(': depth++; break;
                case ')': depth--; break;
                case ',':
                    if (depth == 0) {
                        parts.Add(argsStr.Substring(start, i - start));
                        start = i + 1;
                    }
                    break;
            }
        }
        if (quote != '\0' || depth != 0) return false;
        parts.Add(argsStr.Substring(start));
        foreach (var raw in parts) {
            if (!IsSimpleMSBuildIntrinsicArg(raw.Trim(), allowedQualifier)) return false;
        }
        return true;
    }

    static bool IsSimpleMSBuildIntrinsicArg(string arg) =>
        IsSimpleMSBuildIntrinsicArg(arg, allowedQualifier: null);

    static bool IsSimpleMSBuildIntrinsicArg(string arg, string? allowedQualifier) {
        if (arg.Length == 0) return true;
        if ((arg[0] == '\'' || arg[0] == '"' || arg[0] == '`') && arg.Length >= 2 && arg[arg.Length - 1] == arg[0]) {
            // Inside a quoted intrinsic arg, only `$(SimpleProp)` references
            // and literal text are allowed — mirrors splitIntrinsicArgs ->
            // resolveIntrinsicArg in the runtime. When an allowedQualifier is
            // active, %(qualifier.M) and %(M) references are also accepted.
            return AreSimpleExpansionsOnly(arg.Substring(1, arg.Length - 2), allowedQualifier);
        }
        if (arg.IndexOfAny(new[] { '\'', '"', '`' }) >= 0) return false;
        return AreSimpleExpansionsOnly(arg, allowedQualifier);
    }

    static bool AreSimpleExpansionsOnly(string s) =>
        AreSimpleExpansionsOnly(s, allowedQualifier: null);

    static bool AreSimpleExpansionsOnly(string s, string? allowedQualifier) {
        for (int i = 0; i < s.Length; i++) {
            var c = s[i];
            if (c == '@') {
                if (i + 1 < s.Length && s[i + 1] == '(') return false;
            }
            if (c == '%' && i + 1 < s.Length && s[i + 1] == '(') {
                if (allowedQualifier == null) return false;
                var end = FindMatchingParenQuoteAware(s, i + 1);
                if (end < 0) return false;
                var inner = s.Substring(i + 2, end - i - 2);
                if (!IsValidBatchMetaRef(inner, allowedQualifier)) return false;
                i = end;
                continue;
            }
            if (c == '$' && i + 1 < s.Length && s[i + 1] == '(') {
                var end = FindMatchingParenQuoteAware(s, i + 1);
                if (end < 0) return false;
                var inner = s.Substring(i + 2, end - i - 2);
                if (!IsSimpleExpressionInner(inner, allowedQualifier)) return false;
                i = end;
            }
        }
        return true;
    }

    // IsSimplePropertyExpression accepts either a bare identifier or a property
    // function chain $(Var.M1(...).M2(...).Prop). Mirrors the runtime's
    // evalPropertyExpression. Methods are whitelisted.
    static bool IsSimplePropertyExpression(string inner) {
        inner = inner.Trim();
        if (inner.Length == 0) return true;
        var dot = IndexOfTopLevel(inner, '.');
        if (dot < 0) return IsSimpleIdentifierName(inner);
        var varName = inner.Substring(0, dot).Trim();
        if (!IsSimpleIdentifierName(varName)) return false;
        var rest = inner.Substring(dot + 1);
        while (rest.Length > 0) {
            int nameEnd = 0;
            while (nameEnd < rest.Length) {
                var c = rest[nameEnd];
                var isIdent = char.IsLetterOrDigit(c) || c == '_';
                if (!isIdent) break;
                nameEnd++;
            }
            if (nameEnd == 0) return false;
            var method = rest.Substring(0, nameEnd);
            rest = rest.Substring(nameEnd);
            bool hasArgs = false;
            string[] args = Array.Empty<string>();
            if (rest.Length > 0 && rest[0] == '(') {
                var close = FindMatchingParenQuoteAware(rest, 0);
                if (close < 0) return false;
                hasArgs = true;
                args = SplitArgsQuoteAware(rest.Substring(1, close - 1));
                rest = rest.Substring(close + 1);
            }
            if (!IsWhitelistedPropertyMethod(method, args.Length, hasArgs)) return false;
            foreach (var arg in args) {
                if (!IsSimplePropertyFunctionArg(arg.Trim())) return false;
            }
            rest = rest.Trim();
            if (rest.Length == 0) break;
            if (rest[0] != '.') return false;
            rest = rest.Substring(1);
        }
        return true;
    }

    // IsKnownStringTransformMethod returns true if `method` is one of the
    // string-function names supported by applyPropertyFunction in the
    // runtime. Used by chained-transform validation in IsSimpleTransformRhs;
    // the per-call arg-count + hasArgs validation lives in
    // AreSimpleTransformMethodArgs at the surface level and in
    // applyPropertyFunction at runtime.
    static bool IsKnownStringTransformMethod(string method) {
        switch (method.ToLowerInvariant()) {
            case "tolower":
            case "tolowerinvariant":
            case "toupper":
            case "toupperinvariant":
            case "tostring":
            case "length":
            case "trim":
            case "trimstart":
            case "trimend":
            case "replace":
            case "substring":
            case "startswith":
            case "endswith":
            case "contains":
            case "indexof":
            case "split":
                return true;
            default:
                return false;
        }
    }

    static bool IsWhitelistedPropertyMethod(string method, int argCount, bool hasArgs) {
        switch (method.ToLowerInvariant()) {
            case "tolower":
            case "tolowerinvariant":
            case "toupper":
            case "toupperinvariant":
            case "tostring":
            case "length":
                return !hasArgs || argCount == 0;
            case "trim":
            case "trimstart":
            case "trimend":
                return !hasArgs || argCount <= 1;
            case "replace":
                return hasArgs && argCount == 2;
            case "substring":
                return hasArgs && (argCount == 1 || argCount == 2);
            case "startswith":
            case "endswith":
            case "contains":
            case "indexof":
                return hasArgs && argCount == 1;
            case "split":
                return hasArgs && argCount == 1;
            default:
                return false;
        }
    }

    static bool IsSimplePropertyFunctionArg(string arg) {
        if (arg.Length == 0) return true;
        if ((arg[0] == '\'' || arg[0] == '"') && arg.Length >= 2 && arg[arg.Length - 1] == arg[0]) {
            // Quoted string literal — inner must not contain expansions
            // (`$(...)` / `@(...)` / batching `%(...)`). `%` alone is fine
            // because it shows up in MSBuild's escape encoding (`%3B` == ';',
            // `%24` == '$', etc.). Reject only `%(` since that's the batching
            // metadata reference we don't model in a property-function arg.
            var inner = arg.Substring(1, arg.Length - 2);
            for (int i = 0; i < inner.Length; i++) {
                var ch = inner[i];
                if (ch == '$' || ch == '@') return false;
                if (ch == '%' && i + 1 < inner.Length && inner[i + 1] == '(') return false;
            }
            return true;
        }
        if (arg.StartsWith("$(", StringComparison.Ordinal) && arg.EndsWith(")", StringComparison.Ordinal)) {
            // Single bare $(...) — accept either a simple identifier (Phase B)
            // or a property method chain / intrinsic (Phase H). The classifier
            // mirrors the runtime resolveFunctionArg which now routes nested
            // $() args through evalPropertyExpression/tryEvalIntrinsic.
            var inner = arg.Substring(2, arg.Length - 3);
            return IsSimpleExpressionInner(inner);
        }
        return IsIntegerLiteral(arg);
    }

    static bool IsIntegerLiteral(string s) {
        if (string.IsNullOrEmpty(s)) return false;
        int start = 0;
        if (s[0] == '-' || s[0] == '+') {
            if (s.Length == 1) return false;
            start = 1;
        }
        for (int i = start; i < s.Length; i++) {
            if (s[i] < '0' || s[i] > '9') return false;
        }
        return true;
    }

    static int IndexOfTopLevel(string s, char target) {
        int depth = 0;
        char quote = '\0';
        for (int i = 0; i < s.Length; i++) {
            var c = s[i];
            if (quote != '\0') { if (c == quote) quote = '\0'; continue; }
            switch (c) {
                case '\'': case '"': quote = c; break;
                case '(': depth++; break;
                case ')': if (depth > 0) depth--; break;
                default:
                    if (depth == 0 && c == target) return i;
                    break;
            }
        }
        return -1;
    }

    static string[] SplitArgsQuoteAware(string s) {
        if (string.IsNullOrWhiteSpace(s)) return Array.Empty<string>();
        var parts = new List<string>();
        int depth = 0; char quote = '\0'; int start = 0;
        for (int i = 0; i < s.Length; i++) {
            var c = s[i];
            if (quote != '\0') { if (c == quote) quote = '\0'; continue; }
            switch (c) {
                case '\'': case '"': quote = c; break;
                case '(': depth++; break;
                case ')': depth--; break;
                case ',':
                    if (depth == 0) {
                        parts.Add(s.Substring(start, i - start));
                        start = i + 1;
                    }
                    break;
            }
        }
        parts.Add(s.Substring(start));
        return parts.ToArray();
    }

    static bool IsSimpleConditionTemplate(string? condition) =>
        IsSimpleConditionTemplate(condition, allowedQualifier: null);

    // IsSimpleConditionTemplate returns true when the condition can be
    // evaluated by the runtime cond_eval grammar. When `allowedQualifier`
    // is non-null, `%(Meta)` and `%(allowedQualifier.Meta)` are permitted
    // as operands (per-item batched ItemGroup conditions). Any other `%()`
    // reference is rejected.
    static bool IsSimpleConditionTemplate(string? condition, string? allowedQualifier) {
        if (string.IsNullOrWhiteSpace(condition)) return true;
        // Fast-reject `%()` when batching is not allowed — silent expansion
        // to "" would be wrong-not-loud. Batched callers pass an allowed
        // qualifier and validate each %()-ref explicitly below.
        if (allowedQualifier == null && condition!.Contains("%(", StringComparison.Ordinal)) return false;
        if (!ValidateAllDollarExpansions(condition!, allowedQualifier)) return false;
        // Walk top-level constructs: $(...) must be a simple property expression
        // (Phase A or B form); bare identifiers must be And/Or/Not/True/False or
        // Exists/HasTrailingSlash followed by '('.
        var allowedIdents = new HashSet<string>(StringComparer.OrdinalIgnoreCase) {
            "and", "or", "not", "true", "false", "exists", "hastrailingslash"
        };
        int i = 0;
        char quote = '\0';
        while (i < condition.Length) {
            var c = condition[i];
            if (quote != '\0') {
                if (c == quote) { quote = '\0'; i++; continue; }
                // MSBuild treats `$(...)`, `@(...)`, `%(...)` inside a quoted
                // string as expansion constructs whose inner content is NOT a
                // string terminator. Skip past the matching close paren so the
                // outer quote scan finds the right closing quote — required
                // for conditions like `'@(X->F('a', 'b'))' == ''`.
                if ((c == '$' || c == '@' || c == '%')
                    && i + 1 < condition.Length && condition[i + 1] == '(') {
                    var inEnd = FindMatchingParenQuoteAware(condition, i + 1);
                    if (inEnd < 0) return false;
                    i = inEnd + 1;
                    continue;
                }
                i++;
                continue;
            }
            switch (c) {
                case '<': case '>':
                    // Phase G: numeric / version comparisons (>=, <=, >, <) are
                    // supported by the runtime cond_eval grammar via
                    // NumericCompare. Just skip the operator chars — the
                    // surrounding $() / @() operands are validated separately.
                    if (i + 1 < condition.Length && condition[i + 1] == '=') {
                        i += 2;
                    } else {
                        i++;
                    }
                    continue;
                case '!':
                    // Both `!=` and lone `!<primary>` are supported by the
                    // runtime cond_eval grammar.
                    if (i + 1 < condition.Length && condition[i + 1] == '=') {
                        i += 2;
                    } else {
                        i++;
                    }
                    continue;
                case '\'': case '"': quote = c; i++; continue;
                case '$':
                    if (i + 1 < condition.Length && condition[i + 1] == '(') {
                        var end = FindMatchingParenQuoteAware(condition, i + 1);
                        if (end < 0) return false;
                        var inner = condition.Substring(i + 2, end - i - 2);
                        if (!IsSimpleExpressionInner(inner, allowedQualifier)) return false;
                        i = end + 1;
                        continue;
                    }
                    i++;
                    continue;
                case '%':
                    if (allowedQualifier == null) return false;
                    if (i + 1 >= condition.Length || condition[i + 1] != '(') return false;
                    {
                        var pend = FindMatchingParenQuoteAware(condition, i + 1);
                        if (pend < 0) return false;
                        var pinner = condition.Substring(i + 2, pend - i - 2);
                        if (!IsValidBatchMetaRef(pinner, allowedQualifier)) return false;
                        i = pend + 1;
                    }
                    continue;
                case '@':
                    if (i + 1 < condition.Length && condition[i + 1] == '(') {
                        // Allow @(X), @(X,'sep'), and @(X->Count()) in conditions.
                        var end = FindMatchingParenQuoteAware(condition, i + 1);
                        if (end < 0) return false;
                        var inner = condition.Substring(i + 2, end - i - 2);
                        if (!IsSimpleItemRefInner(inner)) return false;
                        i = end + 1;
                        continue;
                    }
                    i++;
                    continue;
                default:
                    if (char.IsLetter(c) || c == '_') {
                        int wstart = i;
                        while (i < condition.Length && (char.IsLetterOrDigit(condition[i]) || condition[i] == '_')) i++;
                        var word = condition.Substring(wstart, i - wstart);
                        if (!allowedIdents.Contains(word)) return false;
                        // If it's Exists/HasTrailingSlash it must be followed by '('.
                        if (word.Equals("exists", StringComparison.OrdinalIgnoreCase)
                            || word.Equals("hastrailingslash", StringComparison.OrdinalIgnoreCase)) {
                            int j = i;
                            while (j < condition.Length && (condition[j] == ' ' || condition[j] == '\t')) j++;
                            if (j >= condition.Length || condition[j] != '(') return false;
                            var end = FindMatchingParenQuoteAware(condition, j);
                            if (end < 0) return false;
                            // The runtime expands @() inside Exists/HasTrailingSlash via
                            // the standard Expand path (item lists get joined by ';'); we
                            // only need to reject batching refs (`%()`) here, plus any
                            // unsupported transforms inside an @() expansion. The
                            // ValidateAllDollarExpansions pass above already enforced the
                            // @() shape (no transforms, no custom separators).
                            var argSrc = condition.Substring(j + 1, end - j - 1);
                            if (!ValidateBatchMetaRefsInString(argSrc, allowedQualifier)) return false;
                            i = end + 1;
                        }
                        continue;
                    }
                    i++;
                    continue;
            }
        }
        return quote == '\0';
    }

    // ValidateAllDollarExpansions walks `s` (which may be a condition,
    // expression template, or quoted operand) and returns true iff every
    // `$(...)` / `@(...)` / `%(...)` occurrence — regardless of whether it
    // sits inside quotes or outside — is shape-acceptable to the runtime.
    // Specifically: `$(...)` must satisfy IsSimpleExpressionInner; `@(...)`
    // must not contain `->` (transforms unsupported); `%(...)` is rejected
    // anywhere (batching). This pass complements the structural validators
    // by ensuring quoted operands like `'$([MSBuild]::UnsupportedF(...))' == 'x'`
    // or `'@(X->Count())' != '0'` are caught before reaching the runtime
    // (where they would panic).
    static bool ValidateAllDollarExpansions(string s) =>
        ValidateAllDollarExpansions(s, allowedQualifier: null);

    static bool ValidateAllDollarExpansions(string s, string? allowedQualifier) {
        for (int i = 0; i < s.Length; i++) {
            var c = s[i];
            if (c == '$' && i + 1 < s.Length && s[i + 1] == '(') {
                var end = FindMatchingParenQuoteAware(s, i + 1);
                if (end < 0) return false;
                var inner = s.Substring(i + 2, end - i - 2);
                if (!IsSimpleExpressionInner(inner, allowedQualifier)) return false;
                i = end;
                continue;
            }
            if (c == '@' && i + 1 < s.Length && s[i + 1] == '(') {
                var end = FindMatchingParenQuoteAware(s, i + 1);
                if (end < 0) return false;
                var inner = s.Substring(i + 2, end - i - 2);
                if (!IsSimpleItemRefInner(inner)) return false;
                i = end;
                continue;
            }
            if (c == '%' && i + 1 < s.Length && s[i + 1] == '(') {
                if (allowedQualifier == null) return false;
                var end = FindMatchingParenQuoteAware(s, i + 1);
                if (end < 0) return false;
                var inner = s.Substring(i + 2, end - i - 2);
                if (!IsValidBatchMetaRef(inner, allowedQualifier)) return false;
                i = end;
                continue;
            }
        }
        return true;
    }

    // IsValidBatchMetaRef returns true when `inner` (the content between
    // `%(` and `)`) is either a bare identifier (`Meta`) or a qualified
    // reference (`AllowedQualifier.Meta`) where AllowedQualifier matches
    // `allowedQualifier` case-insensitively.
    static bool IsValidBatchMetaRef(string inner, string allowedQualifier) {
        var s = inner.Trim();
        if (s.Length == 0) return false;
        var dot = s.IndexOf('.');
        if (dot < 0) {
            return IsSimpleIdentifierName(s);
        }
        var qual = s.Substring(0, dot).Trim();
        var meta = s.Substring(dot + 1).Trim();
        if (!IsSimpleIdentifierName(qual) || !IsSimpleIdentifierName(meta)) return false;
        return string.Equals(qual, allowedQualifier, StringComparison.OrdinalIgnoreCase);
    }

    // ValidateBatchMetaRefsInString walks `s` looking for `%(...)` chunks
    // and validates each against `allowedQualifier`. When the allowed
    // qualifier is null, any `%(` aborts. Used by the Exists/HasTrailingSlash
    // arg validator to thread the per-item batching context through.
    static bool ValidateBatchMetaRefsInString(string s, string? allowedQualifier) {
        for (int i = 0; i < s.Length; i++) {
            if (s[i] != '%') continue;
            if (i + 1 >= s.Length || s[i + 1] != '(') continue;
            if (allowedQualifier == null) return false;
            var end = FindMatchingParenQuoteAware(s, i + 1);
            if (end < 0) return false;
            var inner = s.Substring(i + 2, end - i - 2);
            if (!IsValidBatchMetaRef(inner, allowedQualifier)) return false;
            i = end;
        }
        return true;
    }

    // ExtractSingleBatchQualifier walks `%(...)` references in `s` and
    // returns the unique qualifier name when every qualified reference
    // uses the same identifier (case-insensitive) and at least one such
    // reference exists. Unqualified references are ignored — they're
    // ambiguous and don't constrain the result. Returns null when there
    // are zero qualified refs, when distinct qualifiers appear, or when
    // any ref is malformed.
    static string? ExtractSingleBatchQualifier(string s) {
        string? found = null;
        for (int i = 0; i + 1 < s.Length; i++) {
            if (s[i] != '%' || s[i + 1] != '(') continue;
            var end = FindMatchingParenQuoteAware(s, i + 1);
            if (end < 0) return null;
            var inner = s.Substring(i + 2, end - i - 2).Trim();
            var dot = inner.IndexOf('.');
            if (dot > 0) {
                var qual = inner.Substring(0, dot).Trim();
                if (!IsSimpleIdentifierName(qual)) return null;
                if (found == null) {
                    found = qual;
                } else if (!string.Equals(found, qual, StringComparison.OrdinalIgnoreCase)) {
                    return null;
                }
            }
            i = end;
        }
        return found;
    }

    static int FindMatchingParenQuoteAware(string s, int openIdx) {
        var depth = 0;
        char quote = '\0';
        for (int i = openIdx; i < s.Length; i++) {
            var c = s[i];
            if (quote != '\0') { if (c == quote) quote = '\0'; continue; }
            switch (c) {
                case '\'': case '"': quote = c; break;
                case '(': depth++; break;
                case ')': depth--; if (depth == 0) return i; break;
            }
        }
        return -1;
    }

    static int FindMatchingParen(string s, int openIdx) => FindMatchingParenQuoteAware(s, openIdx);

    // ContainsBatching returns true when the value contains a `%(...)`
    // expansion OUTSIDE of an `@(...)` item transform RHS. `%()` inside
    // a transform template (e.g. `@(X->'%(Identity)')`) is per-item
    // metadata, not task/target batching, so it must not be treated as
    // a batching marker. Top-level `$(...)` is also walked past to keep
    // `findMatchingParenQuoteAware` semantics aligned with the runtime.
    static bool ContainsBatching(string? value) {
        if (string.IsNullOrEmpty(value)) return false;
        var s = value!;
        for (int i = 0; i < s.Length; i++) {
            var c = s[i];
            // `@(X->'%(M)')` introduces a transform context: `%(M)` inside
            // refers to the transform's per-iteration meta, not real batching
            // on the outer item. Skip past `@(...)` entirely.
            if (c == '@' && i + 1 < s.Length && s[i + 1] == '(') {
                var end = FindMatchingParenQuoteAware(s, i + 1);
                if (end < 0) return true;
                i = end;
                continue;
            }
            // `$(X)` is a property expansion; `%(...)` inside `$()` (e.g.
            // `$([MSBuild]::F(%(Identity)))`) IS real batching — the outer
            // batched item's metadata flows through the intrinsic. Walk into
            // `$()` contents rather than skipping past so the `%(` inside
            // triggers batched emission.
            if (c == '%' && i + 1 < s.Length && s[i + 1] == '(') return true;
        }
        return false;
    }

    static bool HasDynamicExtenderAttr(string? attr) {
        if (string.IsNullOrEmpty(attr)) return false;
        return attr!.IndexOfAny(new[] { '$', '@', '%' }) >= 0;
    }

    // BuildExtenderMaps walks targets in declaration order (the order MSBuild
    // inserted them; later definitions of the same name win, which matches
    // MSBuild's "last definition wins" rule) and constructs two maps:
    //   beforeExtenders[X]: list of target names whose BeforeTargets contains X
    //   afterExtenders[X]:  list of target names whose AfterTargets contains X
    // Targets whose Before/AfterTargets are dynamic ($/@/%) are NOT registered;
    // they get rejected by ClassifyTarget as `before-after-dynamic`. Keys are
    // case-insensitive to match dispatchTarget's lowercase lookup.
    static (Dictionary<string, List<string>> Before, Dictionary<string, List<string>> After)
        BuildExtenderMaps(IEnumerable<ProjectTargetInstance> targetsInDeclarationOrder)
    {
        var before = new Dictionary<string, List<string>>(StringComparer.OrdinalIgnoreCase);
        var after = new Dictionary<string, List<string>>(StringComparer.OrdinalIgnoreCase);
        foreach (var t in targetsInDeclarationOrder) {
            if (!string.IsNullOrEmpty(t.BeforeTargets) && !HasDynamicExtenderAttr(t.BeforeTargets)) {
                foreach (var ext in t.BeforeTargets.Split(';', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)) {
                    if (!before.TryGetValue(ext, out var list)) before[ext] = list = new List<string>();
                    list.Add(t.Name);
                }
            }
            if (!string.IsNullOrEmpty(t.AfterTargets) && !HasDynamicExtenderAttr(t.AfterTargets)) {
                foreach (var ext in t.AfterTargets.Split(';', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)) {
                    if (!after.TryGetValue(ext, out var list)) after[ext] = list = new List<string>();
                    list.Add(t.Name);
                }
            }
        }
        return (before, after);
    }

    // IsSimpleDependsOnTargetsTemplate validates that a DependsOnTargets template
    // contains only literal text and $(...) property expressions. Returns
    // (true, null) when the template can be safely emitted (literal-only or
    // dynamic-via-runtime-Expand); otherwise (false, reason) where reason is
    // the classifier bucket. Phase C accepts $(SimpleProp) and property
    // function chains $(X.Method().Method2()) — anything the runtime's
    // evalPropertyExpression handles. @() and %() are unsupported here
    // because: item-list refs in a depends-on string are unusual enough to
    // defer (would need explicit semantics), and %() outside a batching
    // context silently expands to empty (wrong-not-loud).
    static (bool ok, string? reason) IsSimpleDependsOnTargetsTemplate(string template) {
        if (string.IsNullOrEmpty(template)) return (true, null);
        if (template.Contains("@(", StringComparison.Ordinal)) return (false, "depends-on-item-ref");
        if (template.Contains("%(", StringComparison.Ordinal)) return (false, "depends-on-batching");
        for (int i = 0; i < template.Length; i++) {
            if (template[i] != '$') continue;
            if (i + 1 >= template.Length || template[i + 1] != '(') {
                // Bare `$` is not a recognized MSBuild form here.
                return (false, "depends-on-complex-expression");
            }
            var end = FindMatchingParenQuoteAware(template, i + 1);
            if (end < 0) return (false, "depends-on-complex-expression");
            var inner = template.Substring(i + 2, end - i - 2);
            // Indexers $(X[...]) and registry $(Registry:...) are not supported.
            if (inner.IndexOfAny(new[] { '[', ':' }) >= 0) return (false, "depends-on-complex-expression");
            if (!IsSimplePropertyExpression(inner)) return (false, "depends-on-complex-expression");
            i = end;
        }
        return (true, null);
    }

    static void EmitMain(StringBuilder sb, ProjectInstance instance, IReadOnlyList<string>? requestedTargets) {
        var defaultEntry = requestedTargets is { Count: > 0 } ? requestedTargets[0] : (instance.DefaultTargets.FirstOrDefault() ?? "Build");
        var projectDir = instance.Directory ?? Path.GetDirectoryName(instance.FullPath) ?? ".";
        sb.AppendLine("func main() {");
        sb.AppendLine("\trt.Log.Level = rt.ParseVerbosity(os.Getenv(\"BSHARP_VERBOSITY\"))");
        sb.AppendLine("\trt.ProjectDir = " + GoStringLiteral(projectDir));
        sb.AppendLine("\tif err := os.Chdir(rt.ProjectDir); err != nil {");
        sb.AppendLine("\t\tfmt.Fprintf(os.Stderr, \"bsharp-go-host: chdir(%q) failed: %v\\n\", rt.ProjectDir, err)");
        sb.AppendLine("\t\tos.Exit(2)");
        sb.AppendLine("\t}");
        sb.AppendLine("\tentry := " + GoStringLiteral(defaultEntry));
        sb.AppendLine("\tif len(os.Args) > 1 { entry = os.Args[1] }");
        sb.AppendLine("\tif !dispatchTarget(entry) {");
        sb.AppendLine("\t\tfmt.Fprintf(os.Stderr, \"bsharp-go-host: unknown target %q\\n\", entry)");
        sb.AppendLine("\t\tos.Exit(2)");
        sb.AppendLine("\t}");
        sb.AppendLine("\tif rt.GetErrorList().HasErrors() {");
        sb.AppendLine("\t\tfmt.Fprint(os.Stderr, rt.GetErrorList().FormatSummary())");
        sb.AppendLine("\t\tos.Exit(1)");
        sb.AppendLine("\t}");
        sb.AppendLine("}");
        sb.AppendLine();
        sb.AppendLine("// Reference \"strings\" to keep the import alive when no helper uses it.");
        sb.AppendLine("var _ = strings.ToLower");
    }

    static string BuildGoMod(string runtimeReplacePath) {
        var sb = new StringBuilder();
        sb.AppendLine("module bsharp/generated-host");
        sb.AppendLine();
        sb.AppendLine("go 1.21");
        sb.AppendLine();
        sb.AppendLine("require github.com/simonrozsival/bsharp-host-go v0.0.0");
        sb.AppendLine();
        sb.AppendLine("replace github.com/simonrozsival/bsharp-host-go => " + runtimeReplacePath);
        return sb.ToString();
    }

    static string SanitizeTargetName(string name, HashSet<string> existing) {
        var sb = new StringBuilder("Target_");
        foreach (var c in name) {
            sb.Append(char.IsLetterOrDigit(c) || c == '_' ? c : '_');
        }
        var candidate = sb.ToString();
        var n = 1;
        while (!existing.Add(candidate)) {
            candidate = sb.ToString() + "_" + n++;
        }
        return candidate;
    }

    static string GoStringLiteral(string? value) {
        if (string.IsNullOrEmpty(value)) return "\"\"";
        var sb = new StringBuilder("\"");
        foreach (var c in value) {
            switch (c) {
                case '\\': sb.Append("\\\\"); break;
                case '"':  sb.Append("\\\""); break;
                case '\n': sb.Append("\\n"); break;
                case '\r': sb.Append("\\r"); break;
                case '\t': sb.Append("\\t"); break;
                default:
                    if (c < 0x20) sb.AppendFormat("\\u{0:X4}", (int)c);
                    else sb.Append(c);
                    break;
            }
        }
        sb.Append('"');
        return sb.ToString();
    }

    static string EscapeForGo(string s) => s.Replace("\\", "\\\\").Replace("\"", "\\\"");

    internal sealed class EmitReport {
        public PropertiesReport Properties { get; set; } = new();
        public ItemsReport Items { get; set; } = new();
        public TargetsReport Targets { get; set; } = new();
        public string Note { get; set; } =
            "Phase A scaffold. Real bodies emitted for simple targets; complex ones still panic.";
    }
    internal sealed class PropertiesReport {
        public int Total { get; set; }
        public int SupportedLiteral { get; set; }
    }
    internal sealed class ItemsReport {
        public int TotalTypes { get; set; }
        public int TotalItems { get; set; }
        public int SupportedLiteral { get; set; }
    }
    internal sealed class TargetsReport {
        public int Total { get; set; }
        public int RealBody { get; set; }
        public int StubBody { get; set; }
        public SortedDictionary<string, int> UnsupportedReasons { get; set; } = new(StringComparer.Ordinal);
        public List<RejectedTarget>? Rejected { get; set; }
    }
    internal sealed class RejectedTarget {
        public string Name { get; set; } = "";
        public string Reason { get; set; } = "";
        public string? Detail { get; set; }
    }
}
